    op.create_table('athlete_biomarkers',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('blood_draw_date', sa.DateTime(timezone=True), nullable=False, comment='Data e hora exacta da colheita de sangue (com timezone). Crítico para o painel hormonal: cortisol_am exige colheita 07:00-09:00h (pico CAR — Cortisol Awakening Response). LH/FSH devem ser colhidos em jejum e em repouso (>24h sem exercício intenso). Testosterone total é mais estável mas idealmente matinal. Permite construção de série temporal: baseline pré-época → mid-season → pós-época, rastreando o vetor de adaptação ao longo do tempo.'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('testosterone_total', sa.Float(), nullable=True, comment='Testosterona total sérica. Unidade: nmol/L (ou ng/dL; 1 ng/dL = 0.0347 nmol/L). Referência H: 10.4-34.7 nmol/L (300-1000 ng/dL); F: 0.5-2.6 nmol/L. A testosterona é o principal androgénio anabólico; activa o receptor AR → transcrição de MHC (miosina), IGF-1 local, e inibição da miostatina. Modifica directamente species_endocrine.testosterone_baseline: CPI_T = testosterone_total_atleta / testosterone_tecto_espécie. Valores <8 nmol/L em H → défice androgénico funcional → redução do estímulo anabólico pós-treino em ~30-40%; sinaliza overtreino ou RED-S. Valores >34.7 nmol/L sem explicação fisiológica → protocolo anti-doping.'),
    sa.Column('testosterone_free', sa.Float(), nullable=True, comment='Testosterona livre (fracção biologicamente activa). Unidade: pmol/L ou pg/mL. Referência H: 174-729 pmol/L; F: 3.5-43 pmol/L. Apenas ~2% da testosterona total circula livre; o restante liga-se a SHBG (alta afinidade) e albumina (baixa afinidade). testosterone_free é o modulador real da síntese proteica muscular — um atleta com testosterone_total normal mas SHBG elevada pode ter testosterone_free clinicamente baixa. Calculada por: T_free = T_total × (1 − (SHBG × Ka) / (1 + Ka × SHBG)), ou medida directamente por diálise em equilíbrio (método gold-standard). Interacção com species_endocrine.free_androgen_index.'),
    sa.Column('shbg', sa.Float(), nullable=True, comment='Sex Hormone Binding Globulin. Unidade: nmol/L. Referência H: 16-55 nmol/L; F (pré-menopausa): 25-100 nmol/L. A SHBG liga testosterona e estradiol com alta afinidade, regulando a biodisponibilidade hormonal. SHBG elevada (>70 nmol/L em H) → sequestro de testosterona → redução efectiva do sinal anabólico mesmo com testosterone_total normal. Causas: hipotiroidismo, anorexia, RED-S, estatinas. SHBG reduzida (<10 nmol/L em H) → excesso de androgénios livres; associada a resistência à insulina (HOMA-IR elevado). Modifica o denominador do cálculo de testosterone_free (species_endocrine.shbg_binding_capacity).'),
    sa.Column('estradiol', sa.Float(), nullable=True, comment='Estradiol (E2, 17β-estradiol). Unidade: pmol/L (ou pg/mL; 1 pg/mL = 3.67 pmol/L). Referência H: 40-160 pmol/L; F (fase folicular): 150-750 pmol/L; F (pico ovulatório): até 1800 pmol/L. O estradiol tem papel anabólico e neuroprotetor: estimula IGF-1 hepático, protege a DMO (receptor ERα em osteoblastos), e modula a resposta inflamatória pós-exercício (species_osseous_system.bmd_estrogen_modifier). Em atletas femininas: E2 <100 pmol/L em fase folicular → Tríade (RED-S) → risco imediato de fractura de stress e amenorreia hipotalâmica. Em H: E2 >200 pmol/L → aromatização excessiva (excesso de gordura visceral → aromatase adiposa) → supressão do eixo HPG via feedback negativo.'),
    sa.Column('cortisol_am', sa.Float(), nullable=True, comment='Cortisol matinal sérico (07:00-09:00h). Unidade: nmol/L (ou μg/dL; 1 μg/dL = 27.6 nmol/L). Referência: 138-690 nmol/L (5-25 μg/dL) em colheita matinal. O cortisol é o output final do eixo HPA: CRH → ACTH → cortisol adrenal. O pico matinal (CAR) representa a integridade do ritmo circadiano e a reserva adrenocortical (species_chronobiology.cortisol_awakening_response). CAR elevado (>690 nmol/L) → stress agudo, ansiedade de pré-competição, excesso de treino → estado catabólico: activação de ubiquitina-proteossoma muscular, gluconeogénese a partir de aminoácidos. CAR baixo (<138 nmol/L) → fadiga adrenal / overtreino crónico → perda de variabilidade circadiana → imunossupressão. Rácio testosterone/cortisol > 0.35 nmol/nmol → estado anabólico; <0.20 → estado catabólico de risco (species_endocrine.anabolic_catabolic_ratio).'),
    sa.Column('dhea_s', sa.Float(), nullable=True, comment='DHEA-S (Deidroepiandrosterona-Sulfato). Unidade: μmol/L (ou μg/dL). Referência H 20-30 anos: 5.7-13.4 μmol/L; F 20-30 anos: 2.8-11.0 μmol/L. O DHEA-S é o androgénio adrenal mais abundante; precursor de testosterona e estradiol periféricos (conversão em tecidos alvos via aromatase e 17β-HSD). Declínio fisiológico com a idade (~2%/ano após os 25 anos) — marcador de adrenopausa e reserva funcional adrenal (species_endocrine.dheas_age_trajectory). Em atletas: DHEA-S <3.5 μmol/L em H jovem → deficit adrenal funcional → comprometimento da resposta imunitária inata e da libido. Modifica a fracção de androgénios biodisponíveis para além do eixo HPG.'),
    sa.Column('lh', sa.Float(), nullable=True, comment='LH — Hormona Luteinizante. Unidade: UI/L. Referência H (fase estável): 1.7-8.6 UI/L; F (fase folicular): 2.4-12.6 UI/L. O LH é secretado em pulsos pela hipófise anterior em resposta ao GnRH; em H estimula as células de Leydig → produção de testosterona. LH baixo com testosterone_total baixa → hipogonadismo hipogonadotrópico funcional (overtreino, RED-S, stress crónico) — o problema está no eixo central, não no testículo. LH elevado com testosterone_total baixa → falência testicular primária (espécie rara em atletas jovens). Diagnóstico diferencial essencial para estratégia de intervenção (species_endocrine.hpg_axis_integrity).'),
    sa.Column('fsh', sa.Float(), nullable=True, comment='FSH — Hormona Folículo-Estimulante. Unidade: UI/L. Referência H: 1.5-12.4 UI/L; F (fase folicular): 3.5-12.5 UI/L. Em H, o FSH estimula as células de Sertoli e a espermatogénese. Em F, o FSH regula o desenvolvimento folicular ovariano e a secreção de estradiol. FSH elevado isoladamente → reserva ovárica reduzida em F (marcador de envelhecimento reprodutivo); em H → disfunção tubular testicular. Rácio LH/FSH: em F, <1 na fase folicular precoce é normal; >2 sugere SOP (síndrome do ovário poliquístico). Combinado com LH e estradiol/testosterone → diagnóstico completo do eixo HPG (species_endocrine.hpg_axis_integrity).'),
    sa.Column('hemoglobin', sa.Float(), nullable=True, comment='Hemoglobina sérica. Unidade: g/dL. Referência H: 13.5-17.5 g/dL; F: 12.0-16.0 g/dL. A hemoglobina é o transportador de O₂ no sangue; cada grama transporta 1.34 mL O₂. A capacidade total de transporte de O₂ = Hb × 1.34 × SaO₂. VO2max = CaO₂ × DC = (Hb × 1.34 × SaO₂) × (FC × VS). Hb <13.0 H / <12.0 F → anemia → redução directa do tecto de VO2max (cada 1 g/dL de Hb perdida ≈ 3-4 mL/kg/min de VO2max). Modifica species_hematological.hemoglobin_reference como denominador do CPI hematológico: CPI_Hb = Hb_atleta / Hb_tecto_espécie.'),
    sa.Column('hematocrit', sa.Float(), nullable=True, comment='Hematócrito (fracção de volume de eritrócitos). Unidade: % ou fracção decimal. Referência H: 42-52%; F: 37-47%. O hematócrito determina a viscosidade sanguínea e a resistência vascular: Hct >55% → hiperviscosidade → maior risco trombótico e menor débito cardíaco eficiente (species_cardiovascular.blood_viscosity_threshold). Limiar UCI/WADA: Hct >50% H / >47% F em ciclismo → suspensão preventiva. Hct baixo com Hb normal → hemodiluição (estado de overhydration peri-treino ou expansão de volume plasmático — adaptação desejável ao treino aeróbio). Acompanhar com ferritin e sTfR para distinguir pseudo-anemia de anemia real.'),
    sa.Column('ferritin', sa.Float(), nullable=True, comment='Ferritina sérica. Unidade: μg/L (= ng/mL). Referência funcional para atletas H: 80-200 μg/L; F: 50-150 μg/L. A ferritina é a principal proteína de armazenamento de ferro intracelular; é também reagente de fase aguda (sobe em inflamação, independentemente das reservas de ferro). Ferritina <30 μg/L em atletas → depleção de ferro sem anemia → comprometimento da biogénese mitocondrial (ferro-enxofre clusters), da actividade da ribonucleotide redutase, e da resposta ao EPO (species_hematological.iron_stores_ceiling). Ferritina >300 μg/L → sobrecarga de ferro ou inflamação sistémica; em HFE C282Y AA → hemocromatose activa. Interpretar SEMPRE em conjunto com PCR-hs (se PCR >5 mg/L, ferritina pode estar falsamente elevada).'),
    sa.Column('serum_iron', sa.Float(), nullable=True, comment='Ferro sérico (sideraemia). Unidade: μmol/L (ou μg/dL; 1 μg/dL = 0.179 μmol/L). Referência H: 10.6-28.3 μmol/L; F: 6.6-26.0 μmol/L. O ferro sérico reflecte o ferro ligado à transferrina em circulação — mais variável ao longo do dia (maior de manhã) e mais sensível a ingestão recente do que a ferritina. Baixo ferro sérico com ferritina normal → má absorção intestinal (doença celíaca subclínica, SIBO) ou hepcidin elevada (inflamação crónica). Combinar com transferrin_saturation para diagnóstico diferencial (species_gastrointestinal.iron_absorption_efficiency).'),
    sa.Column('transferrin_saturation', sa.Float(), nullable=True, comment="Saturação da transferrina (TSAT). Unidade: %. Fórmula: TSAT = (Ferro sérico / TIBC) × 100. Referência: 20-45%. TSAT <16% → ferro insuficiente para a eritropoiese → anemia funcional por deficiência de ferro, mesmo com ferritina normal (ferro 'bloqueado' por hepcidin em inflamação) — 'anaemia of inflammation'. TSAT >60% → sobrecarga de ferro (suspeita de hemocromatose ou suplementação excessiva). Diagnóstico diferencial essencial em atletas com Hb baixa: se TSAT <16% → suplementar ferro IV/oral; se TSAT normal → investigar outras causas de anemia (B12, folato, hemólise por impacto do pé — 'footstrike hemolysis' em corredores). Interacção com species_hematological.transferrin_saturation_reference."),
    sa.Column('hba1c', sa.Float(), nullable=True, comment='HbA1c — Hemoglobina glicada. Unidade: % ou mmol/mol (IFCC). Conversão: % = (mmol/mol / 10.929) + 2.15. Referência ideal em atletas: 4.8-5.4% (29-36 mmol/mol). A HbA1c reflecte a glicemia média dos últimos 60-90 dias (vida média do eritrócito ~120 dias; contribuição ponderada: últimos 30d = ~50%). HbA1c <4.8% em atletas de endurance de alto volume → possível anemia hemolítica / turnover aumentado de eritrócitos → HbA1c subestimada. HbA1c >5.7% → pré-diabetes → resistência à insulina → compromisso da captação de glicose muscular mediada por GLUT4 (species_bioenergetics.glucose_transport_efficiency). Atletas com HbA1c >6.0% têm comprometimento significativo da glicogénese hepática e muscular pós-exercício.'),
    sa.Column('fasting_glucose', sa.Float(), nullable=True, comment='Glicemia em jejum (mínimo 8h de jejum). Unidade: mmol/L (ou mg/dL; 1 mg/dL = 0.0556 mmol/L). Referência óptima: 4.0-5.0 mmol/L (72-90 mg/dL). Glicemia em jejum 5.6-6.9 mmol/L → pré-diabetes (ADA 2024). Glicemia em jejum <3.5 mmol/L em repouso → hipoglicemia de jejum → suspeita de hiperinsulinémia, insulinoma, ou síndrome pós-exercício de hipoglicemia retardada (species_bioenergetics.glucoregulation_baseline). Em atletas de endurance: glicemia em jejum ligeiramente mais baixa (3.8-4.6 mmol/L) é fisiológica por maior sensibilidade à insulina e maior captação basal muscular. Interpretar SEMPRE em conjunto com fasting_insulin e HOMA-IR.'),
    sa.Column('fasting_insulin', sa.Float(), nullable=True, comment='Insulina em jejum. Unidade: pmol/L (ou mUI/L; 1 mUI/L = 6.0 pmol/L). Referência óptima em atletas: <60 pmol/L (<10 mUI/L). A insulina é o principal hormona anabólica do metabolismo glucídico: activa PI3K-Akt-mTORC1, GLUT4 translocação, síntese de glicogénio (glycogen synthase) e inibe lipólise. Insulina em jejum elevada (>120 pmol/L) → hiperinsulinémia compensatória → resistência à insulina → captação de glicose GLUT4 comprometida (species_bioenergetics.insulin_sensitivity_index). Insulina muito baixa (<18 pmol/L) com glicemia normal → alta sensibilidade à insulina (fenotípico de atleta de endurance de elite).'),
    sa.Column('homa_ir', sa.Float(), nullable=True, comment='HOMA-IR (Homeostatic Model Assessment of Insulin Resistance). Fórmula: HOMA-IR = (Glucose_jejum_mmol/L × Insulina_jejum_mUI/L) / 22.5. Referência óptima atletas: <1.0; limiar de resistência: >2.5; resistência moderada: >3.5. O HOMA-IR estima a resistência à insulina hepática (supressão da glicogenólise hepática) e muscular (captação de glicose via GLUT4). HOMA-IR >2.5 em atleta → redução da taxa de síntese de glicogénio muscular pós-exercício em ~25-40% → recuperação comprometida e menor disponibilidade de glicose para treinos consecutivos (species_bioenergetics.hepatic_insulin_sensitivity). Interacção directa com apoe_genotype (E4E4 → maior HOMA-IR basal) e com o painel inflamatório (IL-6 e CRP elevados → resistência à insulina mediada por inflamação).'),
    sa.Column('crp_high_sensitivity', sa.Float(), nullable=True, comment='PCR de alta sensibilidade (hs-CRP). Unidade: mg/L. Referência de baixo risco cardiovascular: <1.0 mg/L. Referência óptima atletas: <0.5 mg/L (pré-treino, estado de recuperação). A PCR-hs é sintetizada pelo fígado em resposta a IL-6 e TNF-α; marcador de inflamação sistémica de baixo grau e stress oxidativo crónico. PCR-hs <1.0 mg/L → inflamação de baixo risco; 1-3 mg/L → risco intermédio; >3 mg/L → inflamação sistémica activa. Em atletas, PCR-hs >3 mg/L por >3 semanas consecutivas → sobrecarga imunológica → sobretreinamento inflamatório (species_immune_microbiome.systemic_inflammation_threshold). Falseia ferritina (para cima) e albumina (para baixo) em estados inflamatórios agudos — interpretar todo o painel bioquímico com PCR-hs como covariável de ajuste.'),
    sa.Column('il6_basal', sa.Float(), nullable=True, comment='IL-6 basal (interleucina-6 em repouso, >24h pós-exercício). Unidade: pg/mL. Referência em repouso: <2.0 pg/mL. IMPORTANTE: IL-6 tem efeito bifásico no exercício — durante o exercício muscular actua como miocina pró-metabólica (estimula lipolise e uptake de glicose); em repouso elevada é marcador de inflamação sistémica crónica e activação de macrofagos M1. IL-6 em repouso >5 pg/mL → sinalização pro-inflamatória persistente → activação de SOCS3 → resistência à insulina e resistência ao IGF-1 (species_immune_microbiome.chronic_inflammation_cytokine_threshold e species_endocrine.igf1_signaling_efficiency). IL-6 crónica elevada → activação de HPA (cortisol↑) → catabolismo muscular por via ubiquitina-proteasoma → balanço azotado negativo.'),
    sa.Column('creatine_kinase', sa.Float(), nullable=True, comment='CK — Creatina Quinase total sérica. Unidade: U/L. Referência em repouso (>48h pós-exercício): H <200 U/L; F <170 U/L. A CK é enzima intracelular libertada por dano da membrana miofibrilar; é o marcador mais sensível e específico de dano muscular agudo. CK 200-1000 U/L → dano muscular moderado → 48-72h de recuperação necessárias para restauração da função contráctil (species_musculoskeletal.muscle_damage_recovery_rate). CK >1000 U/L → dano muscular severo / risco de rabdomiólise. CK >10,000 U/L → rabdomiólise activa → risco de insuficiência renal aguda por mioglobinúria (activar protocolo de hidratação intensiva e monitorização renal). Cronicamente elevada em repouso (>500 U/L H / >400 U/L F) em múltiplas colheitas → resposta de dano crónico → overtreino mecânico.'),
    sa.Column('urea', sa.Float(), nullable=True, comment='Ureia sérica (BUN × 2.14 = ureia; ou reportada directamente). Unidade: mmol/L. Referência: 2.5-7.5 mmol/L. A ureia é o produto final do catabolismo de aminoácidos: NH₃ (desaminação) → ciclo da ureia hepático → ureia → excreção renal. Em atletas: ureia pré-treino elevada (>8 mmol/L) → balanço azotado negativo → catabolismo proteico excessivo → ingestão proteica insuficiente ou volume/intensidade de treino excessivo para a ingestão calórica actual (species_protein_metabolism.nitrogen_balance_threshold). Ureia pós-treino pode subir fisiologicamente 20-40% e normalizar em 24h. Ureia cronicamente elevada + creatinina elevada → avaliar função renal (species_renal_excretory.glomerular_filtration_rate). Ureia muito baixa (<2.0 mmol/L) → hiperidratação ou ingestão proteica insuficiente (em atletas plant-based com baixo turnover proteico).'),
    sa.Column('tsh', sa.Float(), nullable=True, comment='TSH — Hormona Estimulante da Tiroide (Tireotrópica). Unidade: mUI/L. Referência laboratorial: 0.4-4.0 mUI/L; óptimo funcional atletas: 1.0-2.5 mUI/L. TSH > 2.5 mUI/L → suspeita de hipotiroidismo subclínico → redução do metabolismo basal (RMR), bradicardia, fadiga, aumento de LDL-C, perturbação do ritmo circadiano de temperatura corporal (species_endocrine.thyroid_function_reference). TSH < 0.4 mUI/L → hipertiroidismo → taquicardia, sudorese, perda de massa muscular, osteopenia. TSH é o melhor screening isolado mas deve ser confirmado com fT3/fT4. Interacção com VDR ff genótipo: défice de vitamina D pode agravar autoimunidade tiroideia (Hashimoto).'),
    sa.Column('ft3_free_triiodothyronine', sa.Float(), nullable=True, comment="fT3 — Tri-iodotironina livre (fracção activa). Unidade: pmol/L. Referência: 3.5-6.5 pmol/L. O T3 livre é a forma biologicamente activa da hormona tiroideia; liga-se ao receptor nuclear TRα (músculo cardíaco e esquelético) e TRβ (fígado, tecido adiposo) → aumento do consumo de O₂ mitocondrial, síntese de β-miosina e SERCA2a. fT3 baixo com TSH elevado → hipotiroidismo periférico. fT3 baixo com TSH normal/baixo → 'Síndrome do T3 baixo' (Low T3 Syndrome) em restrição calórica severa (RED-S) ou doença crónica → redução do RMR (species_bioenergetics.thyroid_metabolic_rate_modifier)."),
    sa.Column('ft4_free_thyroxine', sa.Float(), nullable=True, comment='fT4 — Tiroxina livre (precursor). Unidade: pmol/L. Referência: 10-23 pmol/L. O T4 é convertido perifericamente em T3 activo pela deiodinase tipo 1/2 (D1 hepática e renal; D2 muscular e cerebral). fT4 normal com fT3 baixo → défice de conversão periférica → comum em: défice de selénio (cofactor da deiodinase), stress crónico (cortisol inibe D2), restrição de carbohidratos extrema. Selénio (ver serum_selenium) é cofactor obrigatório das deiodinases (species_endocrine.t4_to_t3_conversion_efficiency).'),
    sa.Column('rt3_reverse_t3', sa.Float(), nullable=True, comment='rT3 — T3 reverso (metabolito inactivo). Unidade: pmol/L. Referência: 0.14-0.54 nmol/L (140-540 pmol/L; verificar unidades do lab). O rT3 é formado pela conversão alternativa de T4 pela deiodinase tipo 3 (inactivadora) em vez da D1/D2 (activadora). rT3 elevado → inibição competitiva do receptor TRα pelo rT3 → hipotiroidismo funcional apesar de TSH/fT4 normais. Causas de rT3 elevado: cortisol crónico elevado (stress/overtreino), défice de ferro (inibe D1), selénio insuficiente, inflamação sistémica. Rácio fT3/rT3 > 2.0 é considerado funcional; < 1.0 → tiroidização periférica comprometida (species_endocrine.rt3_functional_threshold).'),
    sa.Column('ldl_cholesterol', sa.Float(), nullable=True, comment='LDL-C — Colesterol LDL calculado (Friedewald) ou medido directamente. Unidade: mmol/L (ou mg/dL; 1 mg/dL = 0.0259 mmol/L). Referência óptima atletas: < 2.6 mmol/L (<100 mg/dL). LDL-C é o principal marcador de risco aterosclerótico mas tem limitações em atletas com TG < 0.5 mmol/L (Friedewald subestima). Complementar SEMPRE com ApoB (conta partículas aterogénicas directamente). Interacção com APOE genótipo: E4/E4 → LDL-C elevado mesmo com dieta controlada (species_lipid_metabolism.ldl_clearance_rate).'),
    sa.Column('hdl_cholesterol', sa.Float(), nullable=True, comment='HDL-C — Colesterol HDL. Unidade: mmol/L. Referência desejável H: > 1.0 mmol/L; F: > 1.3 mmol/L. O treino aeróbio aumenta HDL-C em média 5-10% por regulação de ABCA1 e LCAT (Lecithin–Cholesterol Acyltransferase). HDL-C elevado em atletas de endurance: 1.8-2.5 mmol/L é comum. species_lipid_metabolism.hdl_reverse_cholesterol_transport.'),
    sa.Column('triglycerides', sa.Float(), nullable=True, comment='Triglicéridos em jejum. Unidade: mmol/L. Referência óptima: < 1.0 mmol/L; limite: < 1.7 mmol/L. TG > 1.7 → metabolismo lipídico comprometido; TG > 5.6 → risco de pancreatite aguda. Em atletas de endurance bem treinados: TG < 0.7 mmol/L é comum (alta actividade de LPL muscular → clearance de quilomicrons eficiente). TG elevados + HDL baixo = padrão de resistência à insulina (síndrome metabólica) — correlacionar com HOMA-IR (species_lipid_metabolism.triglyceride_clearance_rate).'),
    sa.Column('apob', sa.Float(), nullable=True, comment='ApoB — Apolipoproteína B100. Unidade: g/L. Referência desejável: < 0.90 g/L; óptimo: < 0.65 g/L. Cada partícula LDL, VLDL e IDL tem exactamente 1 molécula de ApoB → ApoB conta o número total de partículas aterogénicas (superior ao LDL-C). ApoB é o melhor preditor de risco cardiovascular em atletas com LDL-C pseudo-normal mas partículas LDL pequenas e densas. Interacção directa com APOE genótipo: E4/E4 → ApoB elevado resistente a intervenção dietética (species_cardiovascular.apob_atherogenic_threshold).'),
    sa.Column('lp_a', sa.Float(), nullable=True, comment='Lp(a) — Lipoproteína (a). Unidade: nmol/L (ou mg/dL; preferir nmol/L). Referência de baixo risco: < 75 nmol/L (< 30 mg/dL). Alto risco: > 125 nmol/L (> 50 mg/dL). Lp(a) é determinada geneticamente (LPA gene); não é modificável por dieta ou exercício. Lp(a) elevada → risco aumentado de estenose aórtica calcificada e doença coronária prematura mesmo em atletas jovens. Se Lp(a) > 125 nmol/L → ecocardiograma anual e monitorização de ApoB (species_cardiovascular.lpa_genetic_cardiovascular_risk).'),
    sa.Column('non_hdl_cholesterol', sa.Float(), nullable=True, comment='Não-HDL colesterol = Colesterol total − HDL-C. Unidade: mmol/L. Referência desejável: < 3.4 mmol/L. O não-HDL captura todas as partículas aterogénicas (LDL + VLDL + IDL + Lp(a)) numa única métrica. Mais informativo que LDL-C em jejum incompleto. species_lipid_metabolism.non_hdl_atherogenic_burden.'),
    sa.Column('vitamin_d_25oh', sa.Float(), nullable=True, comment='25-OH-Vitamina D (Calcidiol). Unidade: nmol/L (ou ng/mL; 1 ng/mL = 2.5 nmol/L). Referência óptima atletas: 100-150 nmol/L (40-60 ng/mL). Alvo mínimo: > 75 nmol/L (30 ng/mL). Deficiência: < 50 nmol/L (<20 ng/mL). A vitamina D activa (1,25-OH₂-D, calcitriol) via VDR regula >200 genes: síntese muscular (IGF-1 muscular, receptor androgénio), função imunológica (células Th1/Treg, catelicidina), mineralização óssea (osteocalcina, RANK/RANKL), e expressão de miocina (IL-6, irisin). Défice → redução de força e VO2max, maior risco de fracturas de stress e URTI. Prescrição ajustada por VDR FokI: ff → alvo 125-150 nmol/L; FF → 100-125 nmol/L (species_osseous_system.vitamin_d_bone_mineralization_threshold).'),
    sa.Column('vitamin_b12', sa.Float(), nullable=True, comment='Vitamina B12 (Cobalamina) sérica. Unidade: pmol/L (ou pg/mL; 1 pg/mL = 0.738 pmol/L). Referência funcional: > 300 pmol/L (> 400 pg/mL). Sérico baixo (< 150 pmol/L) com sintomas → défice activo. B12 é cofactor da metionina sintase (remetilação de homocisteína → metionina) e da metilmalonyl-CoA mutase (metabolismo de ácidos gordos de cadeia ímpar). Atletas veganos + MTHFR C677T TT: risco máximo de défice funcional → preferir holotranscobalamina II (B12 activa) como marcador mais sensível. Défice → megaloblastose, hiperhomocisteinémia, desmielinização (species_epigenetic.sam_sah_ratio_reference — SAM depende de B12).'),
    sa.Column('rbc_folate', sa.Float(), nullable=True, comment='Folato eritrocitário (RBC folate). Unidade: nmol/L. Referência: > 340 nmol/L (> 150 ng/mL). O folato eritrocitário reflecte o status de folato dos últimos 120 dias (superior ao folato sérico que varia com ingestão recente). O 5-MTHF (metiltetrahidrofolato) é o substrato da metionina sintase; défice → hiperhomocisteinémia e compromisso de síntese de ADN (eritropoiese). Atletas MTHFR C677T TT necessitam de 5-MTHF (L-metilfolato) em vez de ácido fólico (não conseguem converter eficientemente) (species_epigenetic.sam_sah_ratio_reference).'),
    sa.Column('homocysteine', sa.Float(), nullable=True, comment='Homocisteína total plasmática. Unidade: μmol/L. Referência óptima: < 8 μmol/L; normal: 5-15 μmol/L; hiperhomocisteinémia: > 15 μmol/L. A homocisteína é um aminoácido sulfurado formado a partir de metionina; é remetilada em metionina por B12+folato ou transulfurada para cisteína por B6. Homocisteína > 10 μmol/L → disfunção endotelial, stress oxidativo vascular, activação de NF-κB, oxidação de LDL → risco aterosclerótico (species_cardiovascular.endothelial_homocysteine_threshold). Em atletas: exercício intenso eleva homocisteína transitoriamente; crónica elevada → MTHFR TT + défice B12/folato + baixo SAM/SAH ratio (species_epigenetic.methylation_homocysteine_axis).'),
    sa.Column('omega_3_index', sa.Float(), nullable=True, comment='Índice Ómega-3 (EPA + DHA como % dos ácidos gordos totais em eritrócitos). Unidade: %. Referência de baixo risco cardiovascular: > 8%. Zona de alto risco: < 4%. Zona intermédia: 4-8%. O índice ómega-3 reflecte os últimos 3-4 meses de ingestão de EPA+DHA (integração eritrocitária). EPA → precursor de eicosanóides anti-inflamatórios (PGE3, LTB5, resolvinas E). DHA → componente estrutural das membranas mitocondriais e neurais (fluência). Índice < 4% → membranas eritrocitárias menos fluidas → menor deformabilidade eritrocitária → prejuízo de extracção de O₂ em capilares estreitos (species_hematological.erythrocyte_deformability_modifier). Interacção com FADS1 TT genótipo: necessidade de EPA/DHA pré-formado (species_lipid_metabolism.omega3_membrane_composition_threshold).'),
    sa.Column('rbc_magnesium', sa.Float(), nullable=True, comment='Magnésio intracelular (eritrocitário — RBC Mg). Unidade: mmol/L. Referência RBC: 1.65-2.65 mmol/L. IMPORTANTE: magnésio sérico (normal: 0.75-0.95 mmol/L) é homeostático e não reflecte o status intracelular — um atleta deficiente tem Mg sérico normal mas RBC Mg baixo. Magnésio é cofactor de >300 enzimas: ATP-sintetase (todo o ATP é Mg-ATP), creatina quinase, piruvato quinase, Na+/K+-ATPase, e adenilato ciclase. Défice → cãibras musculares, arritmias, insónia, maior produção de cortisol em resposta a stress (species_endocrine.magnesium_hpa_axis_buffer). Atletas perdem Mg no suor (~0.5-1.0 mmol/L) e na urina em volumes altos.'),
    sa.Column('serum_zinc', sa.Float(), nullable=True, comment='Zinco sérico. Unidade: μmol/L (ou μg/dL; 1 μg/dL = 0.153 μmol/L). Referência: 11-24 μmol/L (70-150 μg/dL). Zinco é cofactor da SOD-Cu/Zn (superóxido dismutase — principal antioxidante citosólico), da testosterona sintase (5α-redutase e aromatase), e da DNA polimerase. Zinco < 9 μmol/L → défice funcional → maior stress oxidativo pós-treino, supressão de testosterone (Mg+Zn juntos → ZMA → relevante em treino de força), comprometimento imunológico (species_endocrine.zinc_testosterone_cofactor e species_oxidative_stress.superoxide_dismutase_zinc_dependency).'),
    sa.Column('serum_selenium', sa.Float(), nullable=True, comment='Selénio sérico. Unidade: μmol/L (ou μg/L; 1 μg/L ≈ 0.013 μmol/L). Referência: 1.0-2.0 μmol/L (80-160 μg/L). Selénio é cofactor obrigatório das selenoproteínas: (1) GPx1/GPx4 (glutationa peroxidase) — neutralização de H₂O₂ e hidroperóxidos lipídicos (species_oxidative_stress.glutathione_peroxidase_activity); (2) Deiodinases D1/D2/D3 — conversão T4→T3 activo; (3) Tioredoxina redutase (TrxR) — regeneração de tioredoxina oxidada. Défice → hipotiroidismo funcional (baixo fT3 por inibição de D2) + maior stress oxidativo mitocondrial pós-treino intenso (species_endocrine.selenium_thyroid_deiodinase_cofactor).'),
    sa.Column('coq10_plasma', sa.Float(), nullable=True, comment='CoQ10 (Coenzima Q10 / Ubiquinol) plasmático. Unidade: μmol/L. Referência jovem adulto: 0.8-1.5 μmol/L; em uso de estatinas: pode cair para < 0.4 μmol/L. CoQ10 é componente integral da cadeia de transporte de electrões mitocondrial (complexos I e II → CoQ10 → complexo III) e antioxidante lipossolúvel da membrana mitocondrial interna. CoQ10 < 0.6 μmol/L → comprometimento da produção de ATP mitocondrial → fadiga muscular prematura e comprometimento da performance aeróbia (species_mitochondrial.electron_transport_chain_efficiency). Síntese endógena requer: HMG-CoA reductase (inibida por estatinas → miopatia por estatinas), tirosina, e mevalonate pathway. Atletas em estatinas: CoQ10 + suplementação são obrigatórios.'),
    sa.Column('nad_nadh_ratio', sa.Float(), nullable=True, comment='Rácio NAD+/NADH em células mononucleares de sangue periférico (PBMC). Rácio óptimo: > 700 (plasma); referência em sangue total varia por método. NAD+ é cofactor obrigatório de: sirtuínas (SIRT1-7 → regulação epigenética e biogénese mitocondrial via PGC-1α), PARP1 (reparação do ADN), e complexos I/III da cadeia respiratória. NAD+ decresce com a idade, com exercício de alta intensidade sem recuperação, e com álcool (conversão para NADH pelo álcool desidrogenase → redução do rácio NAD+/NADH → inibição do ciclo de Krebs). Rácio baixo → menor actividade de SIRT1 → menor biogénese mitocondrial → comprometimento da adaptação ao treino aeróbio (species_mitochondrial.nad_sirtuin_axis_efficiency).'),
    sa.Column('alt', sa.Float(), nullable=True, comment='ALT — Alanina Aminotransferase. Unidade: U/L. Referência H: 7-56 U/L; F: 7-45 U/L. A ALT é enzima intracelular hepática; é o marcador mais específico de lesão hepatocelular (superior à AST em especificidade hepática). ALT elevada em atletas (x2-3 LSN): avaliar com CK — se CK muito elevada, a ALT pode ser de origem muscular (isoenzima muscular de ALT). ALT > 100 U/L sem explicação → biópsia hepática ou ecografia. Esteatose hepática não-alcoólica: ALT/AST > 1.0 + hiperinsulinemia (species_hepatic.hepatocellular_integrity_threshold).'),
    sa.Column('ast', sa.Float(), nullable=True, comment='AST — Aspartato Aminotransferase. Unidade: U/L. Referência H: 10-40 U/L; F: 10-35 U/L. AST existe no fígado, músculo cardíaco, músculo esquelético, rins e cérebro. Rácio AST/ALT (De Ritis): < 1 → hepatite viral/tóxica; > 2 → hepatite alcoólica. AST isolada elevada em atletas de força → origem muscular (CK também elevada). Monitorizar com CK para distinguir lesão hepática de lesão muscular (species_hepatic.liver_enzyme_muscle_context).'),
    sa.Column('ggt', sa.Float(), nullable=True, comment='GGT — Gama-Glutamiltransferase. Unidade: U/L. Referência H: 8-61 U/L; F: 5-36 U/L. GGT é marcador sensível de stress hepático e oxidativo: transfere γ-glutamil da glutationa (GSH) para outros peptídeos → regeneração do precursor de GSH. GGT elevada → steatose hepática, consumo de álcool, medicação (estatinas, paracetamol), stress oxidativo crónico. GGT > 40 U/L + álcool > 7 unidades/semana → síndrome hepática induzida por álcool. Em atletas: GGT pode subir após cargas de treino muito elevadas (species_hepatic.ggt_oxidative_stress_marker).'),
    sa.Column('creatinine', sa.Float(), nullable=True, comment='Creatinina sérica. Unidade: μmol/L (ou mg/dL; 1 mg/dL = 88.4 μmol/L). Referência H: 62-115 μmol/L; F: 44-97 μmol/L. ATENÇÃO em atletas: creatinina é produto da degradação de creatina muscular (1-2% da creatina total/dia → creatinina). Atletas de massa muscular elevada têm creatinina > 115 μmol/L sem comprometimento renal — contexto com lean_mass_kg é obrigatório. Suplementação de creatina monohidratada → creatinina elevada (falso alarme renal). Usar eGFR (calculada por CKD-EPI) em vez de creatinina isolada para avaliação da função renal (species_renal_excretory.glomerular_filtration_rate).'),
    sa.Column('egfr_ckd_epi', sa.Float(), nullable=True, comment='eGFR — Taxa de Filtração Glomerular Estimada (fórmula CKD-EPI 2021). Unidade: mL/min/1.73m². Classificação ERC: G1 ≥ 90 (normal/aumentada); G2 60-89 (ligeiramente diminuída); G3a 45-59; G3b 30-44; G4 15-29; G5 < 15 (falência). eGFR < 60 em atleta → investigar urgente (nefropatia por AINE, rabdomiólise prévia, proteinúria de esforço crónica). eGFR > 90 é esperado em atletas jovens bem hidratados (species_renal_excretory.glomerular_filtration_rate).'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
    op.create_table('athlete_dexa',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('assessment_date', sa.DateTime(timezone=True), nullable=False, comment='Data/hora do scan DEXA ou BIA. Múltiplas linhas por atleta permitem monitorizar a trajectória de recomposição corporal ao longo do tempo. Frequência mínima: trimestral (DEXA completo); mensal (antropometria).'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('total_weight_kg', sa.Float(), nullable=True, comment='Massa corporal total (kg) medida na balança DEXA. Denominador primário para todas as constantes massa-relativas da Fase 1: volume sanguíneo (species_hematological: 70-80 mL/kg H, 60-70 mL/kg M), taxa de sudação máxima (species_thermoregulation: 3 L/h), capacidade de armazenamento de calor (Q = m × c × ΔT, c = 3.47 kJ/kg/°C). Frequência: trimestral (DEXA) / mensal (pesagem).'),
    sa.Column('height_cm', sa.Float(), nullable=True, comment='Estatura em pé (cm). Divisor para IMC (kg/m²), IAMM (kg/m²), Ratio Cintura/Altura, e normalização do VO2max (mL/min/kg). Único na vida após crescimento completo.'),
    sa.Column('bmi_kg_per_m2', sa.Float(), nullable=True, comment="Índice de Massa Corporal = peso(kg) / altura(m)². Fonte: Tabela 3.1 (Eixo 3). Limitado como marcador isolado — 'IMC > 30 com gordura visceral alta é mais informativo que IMC sozinho'. Thresholds WHO: < 18.5 magreza, 18.5-24.9 normal, 25-29.9 excesso, ≥ 30 obesidade. Frequência: mensal (calculado em cada pesagem)."),
    sa.Column('body_surface_area_m2', sa.Float(), nullable=True, comment='Área de superfície corporal (m²) pela fórmula DuBois: 0.007184 × altura_cm^0.725 × peso_kg^0.425. Escala a perda de calor radiativa + convectiva (species_thermoregulation) e a evaporação máxima de suor.'),
    sa.Column('fat_mass_kg', sa.Float(), nullable=True, comment='Massa Gorda Total (kg) por DEXA — Tabela 3.1 (Eixo 3). Soma de depósitos subcutâneo + visceral + ectópico. Particionamento: fat_mass_kg + fat_free_mass_kg = total_weight_kg. Escala o RMR via equação de Cunningham (RMR = 500 + 22 × FFM_kg) e modifica a constante de condutância térmica corpo-casca (species_thermoregulation: 5-75 W/°C). Frequência: trimestral.'),
    sa.Column('body_fat_percentage', sa.Float(), nullable=True, comment="% Massa Gorda = fat_mass_kg / total_weight_kg × 100 — Tabela 3.1 (Eixo 3). '% gordura elevada: maior carga inflamatória de base (adipocinas pró-inflamatórias), maior resistência à insulina, menor VO2max relativo, maior stress articular.' Adiposidade essencial mínima: ~3% homem, ~12% mulher. Performance óptima: 6-13% H, 14-20% M. Modifica: isolamento térmico (↑BF → ↑resistência térmica da casca), aromatização hormonal (↑BF → ↑conversão estrogénica), e coeficiente de sensibilidade à insulina aplicado sobre species_bioenergetics GLUT4 Km. Frequência: trimestral."),
    sa.Column('fat_free_mass_kg', sa.Float(), nullable=True, comment='Massa Livre de Gordura (kg) = lean_mass_kg + bone_mineral_content_kg. Multiplicador primário para: potencial máximo de entrega de O2, TBW estimada (TBW ≈ 0.732 × FFM), taxa de produção de creatinina (20 mg/kg FFM/dia), e RMR de Cunningham. Tecto da espécie: VO2max escala ~50-80 mL/min/kg FFM (species_bioenergetics).'),
    sa.Column('lean_mass_kg', sa.Float(), nullable=True, comment="Massa Magra Total (kg) — tecido mole magro, exclui osso — Tabela 3.1 (Eixo 3). 'Define a capacidade metabólica total (mitocôndrias, enzimas glicolíticas, reservas de glicogénio).' Escala directamente: taxa de síntese proteica de corpo inteiro (species_epigenetic: 280 g/dia a ~70 kg massa magra), FSR muscular, produção de ureia, e força máxima via densidade de pontes cruzadas de miosina (species_neuromuscular)."),
    sa.Column('lean_mass_index_kg_per_m2', sa.Float(), nullable=True, comment='Lean Mass Index (LMI) = lean_mass_kg / altura_m² — Tabela 3.1 (Eixo 3). Normaliza a massa magra total pela estatura. Equivalente ao BMI mas para a componente magra — complementa o IAMM (que considera apenas membros) com a massa magra do tronco e cabeça.'),
    sa.Column('bone_mineral_content_kg', sa.Float(), nullable=True, comment='Conteúdo Mineral Ósseo total (kg) por DEXA — Tabela 3.1 (Eixo 3). Referência: adulto masculino ~2.8 kg, feminino ~2.2 kg. Comparado contra species_osseous_system: cálcio esquelético 1.0 kg (99% do total corporal), fósforo 0.6 kg (85% do total). BMC + lean_mass_kg = fat_free_mass_kg.'),
    sa.Column('bmd_total_g_per_cm2', sa.Float(), nullable=True, comment='DMO corpo total (g/cm²) por DEXA — Tabela 3.1 (Eixo 3). Referência espécie (species_osseous_system): pico L1-L4: 1.0-1.4 g/cm², colo femoral: 0.9-1.2 g/cm². Usada para calcular T-score e escalar risco de fractura contra MESfx = 25.000 µε (lei de Wolff).'),
    sa.Column('bmd_spine_g_per_cm2', sa.Float(), nullable=True, comment='DMO coluna lombar L1-L4 (g/cm²) — Tabela 3.1 (Eixo 3). Referência espécie: pico 1.0-1.4 g/cm². Local primário de diagnóstico de osteoporose: T-score ≤ -2.5 = osteoporose. Frequência: anual (ou semestral em atletas de alto risco).'),
    sa.Column('bmd_femoral_neck_g_per_cm2', sa.Float(), nullable=True, comment='DMO colo femoral (g/cm²) — Tabela 3.1 (Eixo 3). Referência espécie: pico 0.9-1.2 g/cm². Local de fractura de risco. Utilizado com DMO da coluna para calcular score FRAX e condicionar cargas de impacto osteogénico (MESm = 1.250 µε threshold — species_osseous_system).'),
    sa.Column('t_score', sa.Float(), nullable=True, comment="T-score WHO = (DMO individual − DMO média adulto jovem pico) / DP — Tabela 3.1 (Eixo 3). 'T-score < -1.0: osteopénia — limita a carga mecânica máxima aplicável sem risco de fractura de stress. T-score < -2.5: osteoporose — contra-indica cargas de impacto elevadas.' Em atletas jovens com T-score < -1.5 antes dos 30 anos: RED-S ou síndrome da tríade. Frequência: anual."),
    sa.Column('z_score', sa.Float(), nullable=True, comment="Z-score = (DMO individual − DMO média de pares da mesma idade e sexo) / DP — Tabela 3.1. 'Z-score (comparativo com pares de mesma idade) mais relevante em atletas jovens.' Z-score < -2.0 = abaixo do esperado para a idade — separa perda óssea por idade de perda patológica."),
    sa.Column('lean_mass_arms_kg', sa.Float(), nullable=True, comment='Massa magra bilateral dos braços (kg) — Tabela 3.1 (Eixo 3). Componente do ASMM. Reflecte tecido contrátil disponível para força de pressão/puxada. Escala força máxima de preensão e output neuromuscular do membro superior.'),
    sa.Column('lean_mass_legs_kg', sa.Float(), nullable=True, comment='Massa magra bilateral das pernas (kg) — Tabela 3.1 (Eixo 3). Maior componente do ASMM. Determinante primário da força de reacção ao solo, potência de sprint e Wmax em ciclismo. Escala força pico (Fmax ∝ PCSA ∝ massa magra dos membros inferiores — species_neuromuscular).'),
    sa.Column('lean_mass_trunk_kg', sa.Float(), nullable=True, comment='Massa magra do tronco (kg) — Tabela 3.1 (Eixo 3). Inclui erectores espinhais, parede abdominal e musculatura respiratória. Escala a resistência postural, capacidade de pressão intra-abdominal e contribuição muscular respiratória para o limiar ventilatório.'),
    sa.Column('lean_mass_dominant_nondominant_ratio', sa.Float(), nullable=True, comment="Ratio massa magra membro dominante / não-dominante — Tabela 3.1 (Eixo 3). 'Assimetria > 10-15% entre membros: indica padrão de uso desequilibrado ou lesão antiga que compensou; preditor de risco de lesão futura; afecta eficiência biomecânica e transferência de potência.' Frequência: trimestral."),
    sa.Column('lean_mass_limb_asymmetry_percentage', sa.Float(), nullable=True, comment="% de assimetria bilateral de massa magra entre membros homólogos — Módulo D1. 'Uma assimetria de > 10% entre membros homólogos correlaciona-se com risco aumentado de lesão e padrões compensatórios de movimento.' Calculado como: |membro_forte - membro_fraco| / membro_forte × 100. Limiar de risco: > 10% aceitável; > 15% = comprometimento."),
    sa.Column('appendicular_lean_mass_kg', sa.Float(), nullable=True, comment="ASMM (kg) = lean_mass_arms_kg + lean_mass_legs_kg — Tabela 3.1 + Módulo D1. 'Massa Magra Total e Apendicular (DEXA): Define a capacidade metabólica total.' Thresholds de sarcopénia EWGSOP2: H < 20 kg, M < 15 kg. Escala VO2max, output de potência funcional e classificação de risco de queda."),
    sa.Column('appendicular_lean_mass_index_kg_per_m2', sa.Float(), nullable=True, comment="IAMM (kg/m²) = ASMM_kg / altura_m² — Módulo D1: 'Índice de Massa Magra Apendicular (IAMM) = Massa magra membros / Altura².' Target H: > 7.26 kg/m²; M: > 5.50 kg/m². 'Abaixo destes valores: sarcopénia funcional diagnosticável.' Normaliza a massa muscular pela estatura — preditor de performance normalizado por altura superior ao ASMM absoluto. Frequência: trimestral."),
    sa.Column('visceral_fat_android_percentage', sa.Float(), nullable=True, comment="% Gordura Visceral da região android — Tabela 3.1 (Eixo 3). 'Massa Gorda Visceral (Android Fat Ratio ou VAT via DEXA/ressonância): % da gordura android total ou cm² (ressonância: > 100 cm² = elevado risco).' 'Gordura visceral é metabolicamente activa: secreta IL-6, TNF-α, resistina → inflamação sistémica, resistência à insulina, supressão do eixo HPG; preditor independente de comprometimento da recuperação.'"),
    sa.Column('visceral_fat_area_cm2', sa.Float(), nullable=True, comment='Área de gordura visceral (cm²) por DEXA ou TC — Tabela 3.1 (Eixo 3). Threshold de risco elevado: > 100 cm². Correlaciona com deposição ectópica de lípidos no fígado (esteatose hepática) e músculo (IMCL ↑), degradando a eficiência de oxidação mitocondrial de gordura (species_bioenergetics). Frequência: trimestral.'),
    sa.Column('android_fat_percentage', sa.Float(), nullable=True, comment='% gordura da região android (abdominal/cintura) por DEXA — Módulo D1. Gordura android elevada → ↑IL-6 basal (species_immune_microbiome: basal 5 pg/mL), ↑TNF-α, ↑PCR, ↓adiponectina. Threshold de risco metabólico: H > 25%, M > 33%.'),
    sa.Column('gynoid_fat_percentage', sa.Float(), nullable=True, comment='% gordura da região gynoid (anca/coxa) por DEXA — Módulo D1. Depósito glúteo-femoral: fenótipo metabólico protector vs. obesidade android. Gordura gynoid elevada associada a melhor sensibilidade à insulina quando o depósito android é também baixo.'),
    sa.Column('android_gynoid_ratio', sa.Float(), nullable=True, comment="Ratio Android/Gynoid — Módulo D1: 'Ratio Android/Gynoid: Ratio > 1.0 indica deposição preferencial de gordura na região abdominal visceral → maior IL-6 adiposa → maior resistência à insulina.' Índice de risco cardiovascular-metabólico. Escala o multiplicador de citocinas inflamatórias aplicado sobre species_immune_microbiome IL-6, TNF-α, e PCR basais."),
    sa.Column('total_body_water_percentage', sa.Float(), nullable=True, comment="% Água Corporal Total da massa corporal — Tabela 3.1 (Eixo 3). 'Percentagem de Água Corporal Total (TBW): % da massa total (homem jovem: 60-70%; mulher: 50-60%). Hidratação crónica: afecta viscosidade sanguínea, transporte de nutrientes, eficiência da bomba Na⁺/K⁺, termorregulação; TBW cronicamente baixa é sinal de défice de electrólitos ou dieta restritiva.' Frequência: trimestral (via impedância multi-frequência)."),
    sa.Column('total_body_water_liters', sa.Float(), nullable=True, comment='Água Corporal Total (L) por bioimpedância ou diluição de deutério — Tabela 3.1. Estimativa: TBW ≈ 0.60 × peso_kg (H) ou 0.50 × peso_kg (M); mais precisamente TBW ≈ 0.732 × FFM_kg. Escala: volume plasmático (VP ≈ TBW × 0.21), reservatório de suor para termorregulação (species_thermoregulation: taxa máx de suor 3 L/h), e homeostase fluido-electrolítica (species_fluid_electrolyte: distribuição Na⁺/K⁺).'),
    sa.Column('intracellular_water_liters', sa.Float(), nullable=True, comment='Água Intracelular (L) por BIA multi-frequência. Referência: ~60% da TBW. ICW correlaciona com massa celular magra e reflecte o estado de hidratação celular. Ratio ICW/TBW < 0.55: desidratação celular ou catabolismo — modifica o multiplicador de síntese proteica de species_epigenetic.'),
    sa.Column('extracellular_water_liters', sa.Float(), nullable=True, comment='Água Extracelular (L) por BIA multi-frequência. Referência: ~40% da TBW. Inclui água intersticial + plasmática. Ratio ECW/TBW > 0.40: edema, inflamação ou overreaching — aplica penalização inflamatória em species_immune_microbiome e nos cálculos de pré-carga cardiovascular (Frank-Starling).'),
    sa.Column('ecw_tbw_ratio', sa.Float(), nullable=True, comment='Ratio ECW / TBW. Biomarcador de hidratação e inflamação. Intervalo saudável: 0.36-0.39. Valores > 0.40 = edema/inflamação. Valores < 0.35 = desidratação intracelular. Condiciona os algoritmos de prescrição de fluidos e a classificação do estado inflamatório.'),
    sa.Column('waist_height_ratio', sa.Float(), nullable=True, comment="Ratio Cintura/Altura — Tabela 3.1 (Eixo 3). '< 0.50 = baixo risco; > 0.60 = elevado risco metabólico.' 'Indicador simples de adiposidade central; proxy de gordura visceral '  'sem necessidade de DEXA; fortemente correlacionado com inflamação '  'sistémica e resistência à insulina.' Frequência: mensal."),
    sa.Column('phase_angle_degrees', sa.Float(), nullable=True, comment='Ângulo de fase BIA a 50 kHz = arctan(Xc / R). Reflecte integridade da membrana celular e estado nutricional. Referência adulto saudável: 5-7°. Atleta: 7-9°. Crítico: < 4°. Ângulo de fase < 5°: reduz multiplicador de FSR (species_epigenetic) e sinaliza estado catabólico ao motor prescritivo.'),
    sa.Column('reactance_ohm', sa.Float(), nullable=True, comment='Reactância BIA (Ω) a 50 kHz. Reflecte propriedades capacitivas das membranas celulares. Input para o cálculo do ângulo de fase. Referência adulto masculino: ~60-75 Ω.'),
    sa.Column('resistance_ohm', sa.Float(), nullable=True, comment='Resistência BIA (Ω) a 50 kHz. Reflecte condutância de água/electrólitos. Input para ângulo de fase e estimativa de TBW. Referência adulto masculino: ~450-550 Ω.'),
    sa.Column('waist_circumference_cm', sa.Float(), nullable=True, comment='Perímetro da cintura (cm) ao nível do umbigo. Obesidade abdominal WHO: H ≥ 102 cm, M ≥ 88 cm. IDF: H ≥ 94 cm, M ≥ 80 cm. Numerador do waist_height_ratio. Proxy de VAT (r ≈ 0.80 com visceral_fat_area_cm2). Frequência: mensal.'),
    sa.Column('hip_circumference_cm', sa.Float(), nullable=True, comment='Perímetro da anca (cm) no ponto mais largo sobre as nádegas. Denominador do waist_hip_ratio. Frequência: mensal.'),
    sa.Column('waist_hip_ratio', sa.Float(), nullable=True, comment='Ratio cintura/anca. Risco cardiovascular: H ≥ 0.90, M ≥ 0.85. Proxy secundário de gordura visceral quando DEXA não está disponível. Frequência: mensal.'),
    sa.Column('neck_circumference_cm', sa.Float(), nullable=True, comment='Perímetro do pescoço (cm). Rastreio de SAOS: H > 40 cm, M > 35 cm. Risco de apneia do sono → afecta arquitectura de sono (species_chronobiology: %SWS, %REM) e performance cognitiva.'),
    sa.Column('mid_arm_circumference_cm', sa.Float(), nullable=True, comment='Perímetro médio do braço (cm). Proxy de massa magra do membro superior. Limiar de desnutrição: < 23 cm. Atleta masculino de elite: 35-40 cm. Combinado com prega tricipital dá área muscular do braço (cm²).'),
    sa.Column('thigh_circumference_cm', sa.Float(), nullable=True, comment='Perímetro médio da coxa (cm). Proxy do volume quadricípite + isquiotibiais. Correlaciona com lean_mass_legs_kg (r ≈ 0.85). Monitoriza resposta hipertrófica ao treino de força.'),
    sa.Column('calf_circumference_cm', sa.Float(), nullable=True, comment='Perímetro máximo da barriga da perna (cm). Proxy de sarcopénia: < 31 cm = risco sarcopénico (EWGSOP). Escala força do gastrocnémio/sóleo e carga do tendão de Aquiles.'),
    sa.Column('wrist_circumference_cm', sa.Float(), nullable=True, comment='Perímetro do pulso (cm) para classificação de tamanho de esqueleto: pequeno < 15 cm, médio 15-17 cm, grande > 17 cm (H). Modifica o tecto de massa magra potencial no motor prescritivo.'),
    sa.Column('skinfold_triceps_mm', sa.Float(), nullable=True, comment='Prega cutânea tricipital (mm). Face posterior do braço, ponto médio. Componente das equações de 4 locais (Durnin-Womersley) e 7 locais (Jackson-Pollock).'),
    sa.Column('skinfold_biceps_mm', sa.Float(), nullable=True, comment='Prega cutânea bicipital (mm). Face anterior do braço, ponto médio. Componente da equação de Durnin-Womersley de 4 locais.'),
    sa.Column('skinfold_subscapular_mm', sa.Float(), nullable=True, comment='Prega subescapular (mm). Abaixo do ângulo inferior da omoplata. Marcador de gordura subcutânea do tronco. Componente das equações de 4 e 7 locais.'),
    sa.Column('skinfold_suprailiac_mm', sa.Float(), nullable=True, comment='Prega suprailíaca (mm). Acima da crista ilíaca, linha axilar anterior. Componente das equações de 4 e 7 locais.'),
    sa.Column('skinfold_abdominal_mm', sa.Float(), nullable=True, comment='Prega abdominal (mm). 2 cm lateral ao umbigo. Componente da equação de Jackson-Pollock de 7 locais.'),
    sa.Column('skinfold_thigh_mm', sa.Float(), nullable=True, comment='Prega anterior da coxa (mm). Ponto médio da coxa anterior. Componente de Jackson-Pollock 3 locais (H) e 7 locais.'),
    sa.Column('skinfold_chest_mm', sa.Float(), nullable=True, comment='Prega peitoral (mm). Dobra diagonal entre linha axilar anterior e mamilo (H). Componente de Jackson-Pollock 3 e 7 locais.'),
    sa.Column('skinfold_medial_calf_mm', sa.Float(), nullable=True, comment='Prega medial da barriga da perna (mm). Usada em equações de 8 locais e perfil completo ISAK.'),
    sa.Column('sum_of_skinfolds_mm', sa.Float(), nullable=True, comment='Soma de todas as pregas cutâneas medidas (mm). Input para equação de Durnin-Womersley: D = C − M × log(ΣPF). Combinada com equação de Siri (BF% = (4.95/D − 4.50) × 100) para estimar % gordura como validação cruzada do DEXA.'),
    sa.Column('resting_metabolic_rate_kcal_per_day', sa.Float(), nullable=True, comment='RMR medida (kcal/dia) por calorimetria indirecta (gold standard) ou equação de Cunningham: RMR = 500 + 22 × FFM_kg. Referência espécie: ~1.700 kcal/dia a 70 kg de massa magra. RMR individual calibra a taxa de turnover de ATP (species_bioenergetics) e conduz o cálculo do gasto energético total (TEE = RMR × PAL).'),
    sa.Column('respiratory_quotient_rest', sa.Float(), nullable=True, comment='QR de repouso = VCO2 / VO2. Intervalo: 0.70 (oxidação pura de gordura) a 1.00 (oxidação pura de HC). Derivado de calorimetria indirecta. Calibra o ponto de cruzamento de substrato em species_bioenergetics e a taxa de β-oxidação em repouso (species_lipid_metabolism).'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
    op.create_table('athlete_epigenetics',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('assessment_date', sa.Date(), nullable=False, comment='Data da análise epigenética (colheita de sangue para arrays de metilação como Illumina EPIC 850K ou sequenciação de bisulfito WGBS). Permite comparar relógio epigenético ao longo do tempo: DunedinPACE_t2 − DunedinPACE_t1 → velocidade de envelhecimento no período.'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('horvath_clock_age', sa.Float(), nullable=True, comment='Relógio de Horvath (2013) — primeira geração. Unidade: anos. Calculado a partir de 353 CpGs pan-tecidulares (Illumina 450K/EPIC). Delta_Horvath = horvath_clock_age − idade_cronológica: negativo → envelhecimento biológico mais lento que o calendário; positivo → envelhecimento acelerado. Atletas de endurance de elite apresentam delta médio de −3 a −5 anos. Interacção: species_epigenetic.dna_methylation_clock_reference define a trajectória esperada para a idade cronológica da Fase 1. Limitação: insensível a alterações agudas de treino (integra >2 anos).'),
    sa.Column('grimage_biological_age', sa.Float(), nullable=True, comment='Relógio GrimAge (Lu et al., 2019) — segunda geração. Unidade: anos. Treinado em mortalidade all-cause; incorpora 8 proteínas plasmáticas derivadas de metilação (GDF15, PAI1, leptin, TIMP1, ADM, B2M, cystatin-C, pack-years de tabaco proxy). GrimAge é o relógio de mortalidade mais validado: cada ano de grimage_biological_age > idade_cronológica → +15% risco de mortalidade all-cause em 10 anos. species_epigenetic.mortality_risk_methylation_index. Sensível a obesidade, tabagismo, stress crónico e sedentarismo.'),
    sa.Column('dunedinpace_score', sa.Float(), nullable=True, comment='DunedinPACE — Pace of Aging Calculated from the Epigenome. Escala: anos/ano. Calculado a partir de 173 CpGs calibrados no estudo de coorte Dunedin (NZ). Valor médio populaconal = 1.0 (1 ano biológico por 1 ano calendário). DunedinPACE = 0.8 → o atleta envelhece 0.8 anos biológicos por cada ano calendário (envelhecimento lento — perfil desejável). DunedinPACE = 1.2 → aceleração de envelhecimento. Delta_DunedinPACE = score_t2 − score_t1 / Δt → velocidade de mudança. Sensível a intervenções de curto prazo (6-12 meses): exercício aeróbio, restrição calórica, sono, redução de stress. Calcular DunedinPACE_delta = DunedinPACE − 1.0 para o CPI epigenético: species_epigenetic.aging_pace_reference (1.0 = tecto espécie médio).'),
    sa.Column('phenoage_biological_age', sa.Float(), nullable=True, comment="PhenoAge (Levine et al., 2018) — relógio de segunda geração. Unidade: anos. 513 CpGs; treinado em marcadores bioquímicos de envelhecimento fenotípico (albumina, creatinina, glucose, CRP, linfócitos%, volume eritrocitário médio, fosfatase alcalina, glóbulos brancos, idade cronológica). PhenoAge captura a componente inflamatória do envelhecimento epigenético ('inflammaging'). Correlação directa com species_immune_microbiome.chronic_inflammation_threshold: atletas com crp_high_sensitivity cronicamente >2 mg/L tendem a ter PhenoAge 2-4 anos acima da cronológica."),
    sa.Column('telomere_length_kb', sa.Float(), nullable=True, comment='Comprimento médio dos telómeros em leucócitos. Unidade: kb (kilobases). Medição: qPCR (rácio T/S) ou FISH fluxo. Referência 30 anos: ~7-8 kb. Os telómeros encurtam ~50 pb/ano em indivíduos sedentários; atletas de endurance apresentam telómeros 5-10% mais longos que controlos sedentários de mesma idade (espécie: telomerase activada pelo exercício). Telómeros <5 kb → risco de senescência celular prematura → disfunção imunológica e comprometimento de regeneração de células satélite musculares. species_epigenetic.telomere_length_reference define o intervalo esperado para a idade cronológica.'),
    sa.Column('telomere_length_percentile', sa.Float(), nullable=True, comment='Percentil do comprimento telomérico relativo a coorte de mesma idade e sexo. Escala: 0-100. Percentil ≥ 75 → comprimento telomérico preservado para a idade. Percentil < 25 → encurtamento acelerado → investigar causas: stress oxidativo crónico, tabagismo, obesidade, overtreino sem recuperação (interacção com species_oxidative_stress.reactive_oxygen_species_threshold).'),
    sa.Column('global_dna_methylation_percentage', sa.Float(), nullable=True, comment='Metilação global do ADN (5-mC como % do total de citosinas). Medição: ELISA colorimétrico ou LUMA (Luminometric Methylation Assay). Referência: 70-80% de citosinas em contexto CpG estão metiladas no genoma adulto. Hipometilação global (<65%) → activação de elementos transponíveis, instabilidade genómica, risco oncológico. Associada a défice de SAM (S-adenosilmetionina) → défice de folato/B12/B6 (MTHFR C677T TT agrava este risco: species_epigenetic.sam_sah_ratio_reference). Monitorizar em atletas com MTHFR TT + défice vitamínico (ver biomarkers).'),
    sa.Column('sam_sah_ratio', sa.Float(), nullable=True, comment='Rácio SAM/SAH (S-adenosilmetionina / S-adenosilhomocisteína). Medição: HPLC-MS/MS em eritrócitos ou plasma. SAM é o dador universal de grupos metilo para metilação do ADN, ARN e proteínas. SAH é o produto da reacção e inibidor competitivo das metiltransferases. Rácio óptimo: > 4.5 (H: 4-8; F: 4-8 como guia geral). Rácio < 3.0 → compromisso das reacções de metilação → hipermetilação de promotores de genes supressores e hipometilação global simultânea (paradoxo epigenético) → impacta species_epigenetic.sam_sah_ratio_reference. Causas: défice de folato ativo (5-MTHF), B12, B6, betaína, colina; agravado por MTHFR C677T TT e CBS A360A variantes.'),
    sa.Column('elovl2_methylation_percentage', sa.Float(), nullable=True, comment='Metilação do gene ELOVL2 (Elongation of Very Long Chain Fatty Acids 2). Unidade: % metilação em CpGs específicos do promotor. ELOVL2 é um dos CpGs mais altamente correlacionados com a idade cronológica (r > 0.96 em múltiplos estudos). Utilizado como âncora de calibração para os relógios epigenéticos: taxa de metilação ~40% aos 20 anos → ~70% aos 60 anos. Desvio positivo (metilação mais alta que esperado para a idade) → envelhecimento acelerado neste locus específico.'),
    sa.Column('fhl2_methylation_percentage', sa.Float(), nullable=True, comment='Metilação do gene FHL2 (Four and a Half LIM Domains 2). Unidade: % metilação. FHL2 regula a sinalização de androgénios e integrinas no músculo cardíaco e esquelético; a sua metilação aumenta progressivamente com a idade. Em atletas de força: menor metilação de FHL2 correlaciona-se com maior resposta hipertrófica ao treino de resistência (interacção com species_musculoskeletal.hypertrophy_epigenetic_modifier).'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
    op.create_table('athlete_genetics',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('sequencing_date', sa.Date(), nullable=True, comment='Data de recolha da amostra / emissão do relatório de sequenciação. Permite versionar o painel genómico caso o atleta repita o teste com tecnologia mais abrangente (WGS vs SNP array vs painéis direcionados).'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('actn3_r577x', sa.String(length=8), nullable=True, comment="ACTN3 R577X (rs1815739). Genótipos: 'RR' | 'RX' | 'XX'. Alpha-actinina-3, proteína estrutural exclusiva das fibras de contracção rápida (Tipo IIx). RR → expressão máxima de ACTN3 → predomínio Tipo IIx → tecto de força e potência elevado (species_neuromuscular.fast_twitch_fibre_ceiling). RX → heterozigoto; capacidade mista. XX (stop-codon; ~18% população europeia) → ausência de ACTN3 → shift para Tipo I → maior economia metabólica mas tecto de potência absoluta reduzido. Modifica Gradiente_adaptação(força) da Fase 2: XX raramente excedem o percentil 80 em provas explosivas puras."),
    sa.Column('myh7_variant', sa.String(length=16), nullable=True, comment="MYH7 (cadeia pesada de miosina beta — Tipo I). Variantes raras notáveis: 'WT' (wild-type) | 'Arg403Gln' | 'Glu848Gly' | outro código HGVS. MYH7 determina a cinética de ciclagem das pontes cruzadas nas fibras lentas. Mutações de ganho-de-função aumentam força isométrica mas reduzem a velocidade de encurtamento → impacto em species_neuromuscular.isometric_force_max. Clinicamente relevante: variantes patogénicas associadas a miocardiopatia hipertrófica (HCM) — se detectadas deve ser activado o protocolo cardíaco."),
    sa.Column('mstn_variant', sa.String(length=16), nullable=True, comment="MSTN — Miostatina (GDF-8). Variantes: 'WT' | 'K153R' | 'E164K' | outro. A miostatina é o principal inibidor do crescimento muscular; actua sobre Akt/mTOR e inibe a proliferação de células satélite. Variantes LOF (loss-of-function) ou hipomórficas → desinibição de mTORC1 → tecto de hipertrofia elevado (species_musculoskeletal.lean_mass_ceiling). Interacção directa com IGF1 e espera-se sinergismo em K153R + IGF1-192."),
    sa.Column('igf1_promoter_192', sa.String(length=8), nullable=True, comment="IGF1 promotor — polimorfismo CA-repeat (rs35767 proxy: '192/192' | '192/non192' | 'non192/non192'). O alelo 192-bp associa-se a níveis basais de IGF-1 sérico ~20% superiores e maior resposta anabólica ao treino de resistência. Modifica species_endocrine.igf1_baseline e amplia o tecto de resposta de síntese proteica pós-treino. Importante para calibrar a janela anabólica na prescrição nutricional (proteína/leucina)."),
    sa.Column('ace_indel', sa.String(length=4), nullable=True, comment="ACE I/D (rs4646994). Genótipos: 'II' | 'ID' | 'DD'. Polimorfismo de inserção/deleção de 287 pb no intrão 16 do gene da Enzima Conversora de Angiotensina. DD → actividade ACE elevada → maior Angiotensina II → vasoconstrição eficiente, hipertrofia cardíaca favorável para esforços curtos/intensos. II → actividade ACE reduzida → vasodilatação periférica melhorada → superior eficiência em provas longas (correlação com VO2max elite em endurance; species_cardiovascular.vo2max_ceiling). ID → fenotípico intermédio; maior plasticidade de adaptação."),
    sa.Column('ppargc1a_gly482ser', sa.String(length=8), nullable=True, comment="PPARGC1A Gly482Ser (rs8192678). Genótipos: 'GG' | 'GA' | 'AA'. PGC-1α é o co-activador transcricional mestre da biogénese mitocondrial. GG (Gly/Gly) → PGC-1α plenamente funcional → maior densidade mitocondrial induzível por treino → tecto de VO2max e MLSS mais elevado (species_mitochondrial.mitochondrial_density_ceiling). AA (Ser/Ser) → eficiência reduzida de biogénese → resposta ao treino aeróbio atenuada; estes atletas precisam de volumes maiores para atingir a mesma adaptação mitocondrial. Interage sinergicamente com ACE II: II+GG → perfil endurance de elite."),
    sa.Column('vegf_rs2010963', sa.String(length=8), nullable=True, comment="VEGF -634G>C (rs2010963). Genótipos: 'GG' | 'GC' | 'CC'. VEGF (Vascular Endothelial Growth Factor) regula a angiogénese induzida por exercício — capilarização muscular e densidade de capilares/fibra. GG → maior expressão de VEGF → superior capilarização pós-treino → melhor extracção periférica de O₂ (a(v-a)O₂ diff) → amplifica o impacto do VO2max em potência aeróbia sustentada (species_cardiovascular.capillary_density_ceiling)."),
    sa.Column('hif1a_pro582ser', sa.String(length=8), nullable=True, comment="HIF1A Pro582Ser (rs11549465). Genótipos: 'CC' (Pro/Pro) | 'CT' | 'TT' (Ser/Ser). HIF-1α é o factor de transcrição central da resposta hipóxica. Ser582 → degradação proteossómica de HIF-1α mais lenta em normóxia → activação constitutiva parcial da via hipóxica → maior EPO endógena, maior densidade mitocondrial basal, melhor tolerância a altitude. Modifica species_hematological.epo_sensitivity e species_mitochondrial.hypoxia_tolerance_ceiling."),
    sa.Column('ampd1_q12x', sa.String(length=8), nullable=True, comment="AMPD1 Q12X (rs17602729). Genótipos: 'CC' | 'CA' | 'AA'. AMP Deaminase 1 — enzima que converte AMP → IMP no ciclo dos nucleótidos de purina em músculo. AA (homozigoto stop-codon; ~2% população) → deficiência de AMPD1 → acumulação de AMP → maior sinalização AMPK → melhor economia metabólica em esforços prolongados mas risco de cãibras e fadiga prematura em esforços anaeróbios. Interage com species_bioenergetics.atp_resynthesis_rate."),
    sa.Column('mtdna_haplogroup', sa.String(length=8), nullable=True, comment="Haplogrupo do ADN mitocondrial matrilinear. Exemplos: 'H' | 'J' | 'T' | 'U' | 'K' | 'L0' | etc. Haplogrupos J e T associados a maior actividade do complexo I mitocondrial e termogénese desacoplada (UCPs) → vantagem em endurance de altitude e climas frios; ligeira redução de eficiência calórica. Haplogrupo H (mais comum na Europa) → maior eficiência de acoplamento oxidativo → superior rendimento mecânico por mol de O₂. Modifica species_mitochondrial.oxidative_coupling_efficiency."),
    sa.Column('col5a1_rs12722', sa.String(length=8), nullable=True, comment="COL5A1 3'UTR BstUI RFLP (rs12722). Genótipos: 'CC' | 'CT' | 'TT'. Colagénio tipo V — componente estrutural dos tendões e ligamentos; regula o diâmetro das fibrilas de colagénio tipo I. TT → maior rigidez tendinosa → melhor transmissão de força e menor risco de tendinopatia patellar/Aquiles. CC → fibrilas mais finas → maior laxidez ligamentar → risco aumentado de entorses e rotura do LCA (species_musculoskeletal.connective_tissue_integrity). Essencial para estratificar o volume de treino pliométrico e a progressão de cargas excêntricas."),
    sa.Column('col1a1_sp1', sa.String(length=8), nullable=True, comment="COL1A1 Sp1 binding site (rs1800012). Genótipos: 'GG' | 'GT' | 'TT'. Colagénio tipo I — principal proteína estrutural do osso e tendão. TT → menor expressão de COL1A1 → densidade mineral óssea reduzida e maior fragilidade tendinosa → risco de fractura de stress (species_osseous_system.bmd_ceiling). GG → arquitectura óssea e tendinosa óptima. Em atletas TT, a suplementação de colágeno + vit C tem maior impacto relativo na síntese de colagénio tendinoso."),
    sa.Column('mmp3_rs679620', sa.String(length=8), nullable=True, comment="MMP3 5A/6A (rs679620 proxy). Genótipos: '5A5A' | '5A6A' | '6A6A'. Metaloproteinase-3 — enzima de remodelação da matriz extracelular do tendão. 5A5A → maior actividade MMP3 → degradação mais rápida de colagénio danificado → maior taxa de remodelação tendinosa pós-treino excêntrico; mas também maior susceptibilidade à tendinopatia crónica se recuperação insuficiente. Modifica o período mínimo de recuperação entre sessões de carga tendinosa máxima (species_musculoskeletal.tendon_remodeling_rate)."),
    sa.Column('gdf5_rs143384', sa.String(length=8), nullable=True, comment="GDF5 (Growth Differentiation Factor 5) rs143384. Genótipos: 'AA' | 'AG' | 'GG'. GDF5 regula a diferenciação condrogénica e a morfogénese articular. AA → expressão reduzida → risco aumentado de osteoartrite, em particular do joelho; menor capacidade regenerativa da cartilagem articular. GG → expressão plena → articulações mais resilientes. Informa a prescrição do volume de impacto acumulado semanal e a monitorização de biomarcadores de cartilagem (COMP, s-GAG)."),
    sa.Column('tnxb_rs1061496', sa.String(length=8), nullable=True, comment="TNXB (Tenascina-X) rs1061496. Genótipos: 'AA' | 'AG' | 'GG'. Tenascina-X é uma glicoproteína da matriz extracelular que regula a organização das fibrilas de colagénio e a viscoelasticidade dos tecidos moles. Variantes LOF associadas à síndrome de Ehlers-Danlos hipermóvel (hEDS). Alelo A → hiperlaxidez ligamentar, instabilidade articular, maior risco de entorses recorrentes. Crucial para definir o programa de estabilização neuromuscular e os limites de amplitude em exercícios de mobilidade (species_musculoskeletal.joint_laxity)."),
    sa.Column('mthfr_c677t', sa.String(length=8), nullable=True, comment="MTHFR C677T (rs1801133). Genótipos: 'CC' | 'CT' | 'TT'. 5,10-metilenotetra-hidrofolato redutase — enzima central no ciclo do folato e na remetilação da homocisteína em metionina. TT → actividade enzimática reduzida ~70% → risco de hiper-homocisteinémia → stress oxidativo vascular e disfunção mitocondrial. Impacta species_oxidative_stress.homocysteine_ceiling e species_epigenetic.sam_sah_ratio (disponibilidade de SAM para metilação do ADN). Prescrição: 5-MTHF (metilfolato activo) em vez de ácido fólico sintético; metilcobalamina B12; monitorização de homocisteína sérica (alvo <8 μmol/L)."),
    sa.Column('mthfr_a1298c', sa.String(length=8), nullable=True, comment="MTHFR A1298C (rs1801131). Genótipos: 'AA' | 'AC' | 'CC'. Segundo polimorfismo funcional do MTHFR; afecta a conversão de 5-MTHF em THF (tetrahidrofolato) e a síntese de BH4 (tetrahidrobiopterina). CC → redução na biossíntese de BH4 → menor síntese de neurotransmissores dopaminérgicos e serotoninérgicos → impacta species_neural_cognitive.neurotransmitter_baseline. Composto heterozigoto C677T/A1298C → efeito cumulativo significativo; suplementação prioritária de 5-MTHF + B6 (P5P) + B12 (metil)."),
    sa.Column('comt_val158met', sa.String(length=8), nullable=True, comment="COMT Val158Met (rs4680). Genótipos: 'GG' (Val/Val) | 'GA' | 'AA' (Met/Met). Catecol-O-Metiltransferase — enzima que degrada dopamina, adrenalina e noradrenalina no córtex pré-frontal. AA (Met/Met) → actividade COMT ~40% inferior → maior disponibilidade de dopamina pré-frontal → melhor working memory e tomada de decisão sob carga cognitiva moderada (species_neural_cognitive.prefrontal_dopamine_clearance). GG (Val/Val) → clearance rápida → maior resiliência em stress agudo, 'guerreiro' vs 'preocupado': melhor performance sob pressão competitiva extrema. AA sob stress intenso → hiperdopaminergia prefrontal → ansiedade e degradação de performance (paradoxo). Informa estratégias de gestão de arousal e uso de adaptógenos."),
    sa.Column('cyp1a2_rs762551', sa.String(length=8), nullable=True, comment="CYP1A2 -163C>A (rs762551). Genótipos: 'AA' | 'AC' | 'CC'. CYP1A2 é a isoenzima hepática responsável por ~95% do metabolismo da cafeína (1,3,7-trimetilxantina → paraxantina). AA → metabolizador rápido → t½ cafeína ~3-4h → ergogenic effect limpo, janela óptima: 60 min pré-treino, sem interferência no sono se tomada antes das 14h (species_chronobiology.caffeine_half_life = curto). CC → metabolizador lento → t½ cafeína ~7-12h → risco de acumulação, perturbação do sono, e — paradoxalmente — aumento do risco cardiovascular em doses >200 mg/d. Prescrição: dose máxima 100 mg em metabolizadores lentos."),
    sa.Column('vdr_foki', sa.String(length=8), nullable=True, comment="VDR FokI (rs2228570). Genótipos: 'FF' | 'Ff' | 'ff'. Polimorfismo no codão de iniciação do Receptor da Vitamina D. ff → proteína VDR 3 aa mais longa → menor eficiência de transactivação → menor sensibilidade à vitamina D → necessidade de níveis séricos de 25(OH)D mais elevados para atingir a mesma resposta imunológica, óssea e muscular (species_osseous_system.vitamin_d_sensitivity e species_immune_microbiome.vitamin_d_receptor_efficiency). ff requer 25(OH)D sérico alvo ≥50 ng/mL vs FF onde 40 ng/mL é suficiente."),
    sa.Column('fads1_rs174537', sa.String(length=8), nullable=True, comment="FADS1 rs174537. Genótipos: 'GG' | 'GT' | 'TT'. FADS1 (Delta-5-desaturase) e FADS2 (Delta-6-desaturase) controlam a conversão de ALA → EPA → DHA (ácidos gordos ómega-3 de cadeia longa). TT → actividade desaturase reduzida → conversão endógena ALA→DHA muito ineficiente (<5%) → dependência absoluta de EPA/DHA pré-formado (peixe gordo, suplemento de óleo de algas/peixe). Modifica species_lipid_metabolism.omega3_conversion_efficiency. Impacto directo na resolução de inflamação pós-treino e na fluidez das membranas mitocondriais (species_mitochondrial.membrane_composition)."),
    sa.Column('hfe_c282y', sa.String(length=8), nullable=True, comment="HFE C282Y (rs1800562). Genótipos: 'GG' (WT) | 'GA' | 'AA'. HFE — gene da hemocromatose hereditária. AA (homozigoto) → absorção intestinal de ferro desregulada → acumulação progressiva de ferro → hemossiderose hepática, cardíaca, articular. Em atletas de endurance: GA heterozigoto pode conferir vantagem de absorção de ferro e menor risco de anemia ferropénica, mas requer monitorização de ferritina (alvo 80-150 ng/mL; species_hematological.iron_stores_ceiling). AA exige restrição de suplementação de ferro e flebotomia terapêutica se ferritina >300 ng/mL."),
    sa.Column('hfe_h63d', sa.String(length=8), nullable=True, comment="HFE H63D (rs1799945). Genótipos: 'CC' (WT) | 'CG' | 'GG'. Segundo polimorfismo funcional do HFE; efeito mais moderado que C282Y. Composto heterozigoto C282Y/H63D → risco intermédio de sobrecarga de ferro. GG homozigoto → absorção de ferro aumentada em ~20-30%; monitorização trimestral de ferritina e saturação da transferrina em atletas de endurance de alto volume (>12h/sem)."),
    sa.Column('lct_rs4988235', sa.String(length=8), nullable=True, comment="LCT -13910C>T (rs4988235). Genótipos: 'CC' | 'CT' | 'TT'. Persistência da lactase — capacidade de digerir lactose na idade adulta. CC → não-persistência (hipolactasia do adulto) → intolerância à lactose → sintomas GI em contexto de ingestão peri-treino de whey/caseína; impacta species_gastrointestinal.lactase_persistence. TT → persistência plena → produtos lácteos bem tolerados → fonte proteica e de cálcio sem restrição. CT → persistência parcial; tolerância variável (limiar ~12 g lactose/refeição)."),
    sa.Column('apoe_genotype', sa.String(length=8), nullable=True, comment="ApoE genótipo combinado. Valores: 'E2E2' | 'E2E3' | 'E2E4' | 'E3E3' | 'E3E4' | 'E4E4'. Apolipoproteína E — ligante de lipoproteínas; determina a clearance de lipoproteínas ricas em triglicéridos e LDL-C. E4 → clearance de LDL reduzida → LDL-C e ApoB mais elevados em dietas ricas em gordura saturada → risco cardiovascular elevado (species_lipid_metabolism.ldl_clearance_rate e species_cardiovascular.atherosclerosis_risk_modifier). E2 → clearance aumentada → LDL-C mais baixo; mas em E2E2 risco de hiperlipoproteinémia tipo III. E4E4 → requer dieta muito baixa em gordura saturada e monitorização lipídica semestral."),
    sa.Column('bcmo1_rs7501331', sa.String(length=8), nullable=True, comment="BCMO1 (BCO1) rs7501331. Genótipos: 'CC' | 'CA' | 'AA'. Beta-caroteno-15,15'-mono-oxigenase — enzima intestinal que converte β-caroteno (provitamina A) em retinal (vitamina A activa). AA → actividade enzimática reduzida ~69% → conversão insuficiente de β-caroteno em retinol → dependência de vitamina A pré-formada (fígado, óvos, suplemento de retinol) em dietas plant-based (species_gastrointestinal.carotenoid_conversion_efficiency). Relevante para função imunológica e integridade epitelial intestinal (species_immune_microbiome.mucosal_barrier_integrity)."),
    sa.Column('clock_rs1801260', sa.String(length=8), nullable=True, comment="CLOCK 3111T>C (rs1801260). Genótipos: 'TT' | 'TC' | 'CC'. CLOCK é a subunidade do heterodímero CLOCK:BMAL1 que activa a transcrição dos genes do relógio circadiano (Per, Cry, Rev-erb). CC → período circadiano endógeno mais longo (~24.5h) → tendência vespertina (cronotipo tardio, 'coruja'); atraso de fase de temperatura corporal e cortisol. Performance pico deslocada para tarde (16-20h). TT → período mais curto → cronotipo matutino; pico de performance ~9-12h. Informa o agendamento óptimo de treinos e competições (species_chronobiology.circadian_period e phase_shift_sensitivity)."),
    sa.Column('per2_rs2304672', sa.String(length=8), nullable=True, comment="PER2 rs2304672. Genótipos: 'CC' | 'CG' | 'GG'. Period-2 — gene efector da ansa negativa do relógio circadiano; regula a supressão de CLOCK:BMAL1 com período de ~24h. Variantes em PER2 associadas a FASPS (Familial Advanced Sleep Phase Syndrome) → cronotipo extremamente matutino; sono iniciado 19-21h, despertar 3-5h AM. Em atletas: janela de treino óptima 06-10h; vigilância para overtreino vespertino que pode deslocar a fase circadiana."),
    sa.Column('per3_vntr', sa.String(length=8), nullable=True, comment="PER3 VNTR (rs57875989). Genótipos: '4/4' | '4/5' | '5/5'. Variable Number Tandem Repeat de 54 pb no exão 18 do gene PER3. 5/5 → maior sensibilidade à privação de sono → declínio mais acentuado em vigilância psicomotora (PVT) após noite de privação parcial (<6h). Também associado a maior supressão de melatonina pela luz azul nocturna. (species_chronobiology.sleep_pressure_sensitivity). 5/5 requer higiene de sono rigorosa: extinção de luz azul 2h antes do sono, blackout total, temperatura quarto 18-19°C."),
    sa.Column('slc6a4_5httlpr', sa.String(length=8), nullable=True, comment="SLC6A4 5-HTTLPR (transportador de serotonina). Genótipos: 'LL' | 'LS' | 'SS' (alelos L=longo, S=curto). 5-HTTLPR regula a expressão do transportador de recaptação de serotonina (SERT) no terminal pré-sináptico. SS → expressão SERT reduzida → maior disponibilidade sináptica de 5-HT basal mas menor tampão em situações de stress → hiperreactividade à adversidade; maior prevalência de ansiedade de pré-competição e PTSD pós-lesão grave (species_neural_cognitive.serotonin_reuptake_efficiency). LL → recaptação eficiente → maior homeostasia serotoninérgica; melhor resiliência a stressores crónicos (overtreino, viagens, jet lag)."),
    sa.Column('bdnf_val66met', sa.String(length=8), nullable=True, comment="BDNF Val66Met (rs6265). Genótipos: 'GG' (Val/Val) | 'GA' | 'AA' (Met/Met). Brain-Derived Neurotrophic Factor — neurotrofina essencial para neuroplasticidade, consolidação de memória motora e resposta ao exercício. GG → secreção actividade-dependente de BDNF plena → maior neuroplasticidade induzida por exercício → aprendizagem técnica mais rápida (species_neural_cognitive.bdnf_exercise_response). AA → secreção reduzida ~30% → menor resposta neurotrófica ao exercício aeróbio; risco aumentado de depressão pós-lesão prolongada. Exercício aeróbio (30 min, ≥65% VO2max) é o estímulo mais potente de BDNF para AA; prescrição deve incluir componente aeróbio diário mínimo."),
    sa.Column('oprm1_a118g', sa.String(length=8), nullable=True, comment="OPRM1 A118G (rs1799971). Genótipos: 'AA' | 'AG' | 'GG'. Receptor opióide mu-1 — principal receptor de β-endorfina e opioides endógenos; central na modulação da dor e no 'runner's high'. GG → receptor com maior afinidade para β-endorfina (3x) → maior analgesia endógena → tolerância à dor muscular mais elevada em treinos de alta intensidade; maior euforia pós-exercício (species_neural_cognitive.pain_threshold). AA → resposta opióide basal; sem alteração. Relevante para gestão de analgésicos em pós-cirúrgico (resposta reduzida a opioides exógenos em GG)."),
    sa.Column('drd2_taq1a', sa.String(length=8), nullable=True, comment="DRD2 TaqIA (rs1800497). Genótipos: 'A1A1' | 'A1A2' | 'A2A2'. Polimorfismo no gene ANKK1 (flanco 3' de DRD2) que reduz a densidade de receptores D2 no estriado. A1A1 → ~30-40% menos receptores D2 → hipodopaminergia estriatal → menor sensação de recompensa intrínseca, maior drive para busca de novidade e estimulação externa → risco de comportamentos de risco e menor adesão a protocolos repetitivos de treino de base. (species_neural_cognitive.reward_circuit_sensitivity). A2A2 → densidade D2 normal → maior satisfação com progressão gradual; melhor tolerância a treinos de alto volume monótono (endurance base)."),
    sa.Column('polygenic_endurance_score', sa.Float(), nullable=True, comment='Score poligénico de capacidade aeróbia/endurance. Escala 0.0-1.0. Calculado externamente combinando: ACE (II=+2, ID=+1, DD=0), PPARGC1A (GG=+2, GA=+1, AA=0), HIF1A (CT/TT=+1), VEGF (GG=+1), mtDNA haplogroup (J/T=+1). Score ≥ 0.7 → perfil genético favorável para endurance de elite. Modifica o tecto individual de VO2max (species_cardiovascular.vo2max_ceiling) como fracção do tecto da espécie: VO2max_tecto_individual = VO2max_espécie × (0.8 + 0.2 × polygenic_endurance_score).'),
    sa.Column('polygenic_power_score', sa.Float(), nullable=True, comment='Score poligénico de potência/força explosiva. Escala 0.0-1.0. Calculado externamente combinando: ACTN3 (RR=+2, RX=+1, XX=0), ACE (DD=+2, ID=+1, II=0), IGF1-192 (192/192=+2), MSTN LOF (=+2), AMPD1 (CC=+1). Score ≥ 0.7 → perfil genético favorável para desportos de potência/força. Modifica species_neuromuscular.peak_power_ceiling como multiplicador.'),
    sa.Column('polygenic_injury_risk_score', sa.Float(), nullable=True, comment='Score poligénico de risco de lesão músculo-esquelética. Escala 0.0-1.0 (0 = menor risco, 1 = maior risco). Calculado combinando: COL5A1 (CC=+2, CT=+1, TT=0), COL1A1 (TT=+2, GT=+1), GDF5 (AA=+2, AG=+1), TNXB A (=+1), MMP3 5A5A (=+1). Score ≥ 0.6 → protocolo de prevenção de lesão obrigatório: excêntrico progressivo, colágeno + vit C 1h pré-treino, ultrassom tendinoso semestral. Informa o volume máximo de impacto semanal (species_musculoskeletal.injury_risk_threshold).'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id'),
    sa.UniqueConstraint('athlete_id'),
    sa.UniqueConstraint('athlete_id', name='uq_athlete_genetics_athlete')
    )
    op.create_table('athlete_history',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('last_updated', sa.Date(), nullable=False, comment='Data da última actualização do historial (rever a cada 3-6 meses).'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('primary_sport', sa.String(length=128), nullable=True, comment="Modalidade desportiva principal actual. Exemplos: 'Ciclismo de Estrada', 'Triatlo', 'Futebol', 'Levantamento de Pesos', 'Natação'. Determina quais os sistemas fisiológicos prioritários e quais os tectos species_* mais relevantes para o CPI primário do atleta."),
    sa.Column('secondary_sport', sa.String(length=128), nullable=True, comment='Modalidade desportiva secundária ou histórica relevante. Ex: ex-atleta de natação que transicionou para triatlo — o background de natação informa a reserva cardiovascular e técnica aquática.'),
    sa.Column('training_age_years', sa.Float(), nullable=True, comment='Idade de treino — anos de treino sistemático e estruturado na modalidade principal (ou modalidade base). Unidade: anos decimais. A idade de treino é o modificador mais importante do Gradiente de adaptação: Gradiente_adaptação = (Tecto_Individual − Baseline) / Tecto_Individual. Iniciante (< 2 anos): gradiente alto → grandes ganhos com pequenos estímulos. Intermédio (2-5 anos): ganhos moderados; periodização necessária. Avançado (5-10 anos): ganhos requerem sobrecarga progressiva e variação. Elite (> 10 anos): margens de progressão estreitas; pequenos ganhos requerem intervenções altamente específicas e individualizadas. Calibra a taxa de progressão esperada em todos os sistemas da Fase 2.'),
    sa.Column('competition_level', sa.String(length=64), nullable=True, comment="Nível competitivo actual. Valores: 'recreational' | 'regional' | 'national' | 'international' | 'elite_professional' | 'olympic'. Informa o contexto de comparação para os CPIs e os thresholds de intervenção (ex: um VO2max de 55 mL/kg/min é excelente para regional mas insuficiente para elite internacional em endurance)."),
    sa.Column('sport_start_date', sa.Date(), nullable=True, comment='Data de início do treino sistemático na modalidade actual. Permite calcular training_age_years de forma automática se não fornecido: training_age_years = (assessment_date − sport_start_date).years.'),
    sa.Column('weekly_training_hours', sa.Float(), nullable=True, comment='Volume semanal médio de treino (últimas 4-8 semanas). Unidade: horas. Referência: recreativo 5-10h; alto rendimento 12-20h; elite 20-35h. Contextualiza os biomarkers de stress (CK, urea, cortisol) e o RMSSD: um RMSSD de 45ms em atleta de 20h/sem é diferente de 45ms em atleta de 8h/sem.'),
    sa.Column('weekly_training_sessions', sa.Integer(), nullable=True, comment='Número médio de sessões de treino por semana. Referência: recreativo 3-5; alto rendimento 6-10; elite 10-16 (bi-diário). Número de sessões determina a janela de recuperação inter-sessão: 2 sessões/dia → <12h de recuperação → biomarkers de dano crónico (CK crónico >500 U/L) são mais toleráveis.'),
    sa.Column('periodization_phase', sa.String(length=64), nullable=True, comment="Fase de periodização actual. Valores: 'base' | 'build' | 'peak' | 'competition' | 'transition' | 'rehabilitation'. Crítico para interpretar todos os clusters: na fase de 'build' esperam-se marcadores de fadiga mais elevados (CK, urea, RMSSD baixo) que na fase 'peak' ou 'competition'."),
    sa.Column('altitude_training_history', sa.Boolean(), nullable=True, comment='True se o atleta tem histórico de treino em altitude (>2000m) ou em tenda hipóxica nas últimas 12 semanas. Altitude → eritropoiese estimulada por HIF1α/EPO → Hb e ferritina transitoriamente elevadas pós-campo (até 3-4 semanas). Interpreta Hb e Hct com cautela se altitude_training_history = True (species_hematological.altitude_erythropoiesis_modifier).'),
    sa.Column('injury_history_summary', sa.Text(), nullable=True, comment="Resumo narrativo de lesões musculoesqueléticas relevantes. Formato sugerido: 'Rotura parcial LCA joelho D (2021, cirurgia), tendinopatia patelar bilateral (2023, conservador)'. Informa: (1) risco de recidiva e thresholds de volume seguros; (2) interpretação de assimetrias biomecânicas (CMJ, IMTP, dorsiflexão); (3) selecção de exercícios de prevenção prioritários. Para lesões complexas, criar registo estruturado separado (fora do BOS)."),
    sa.Column('fractures_stress_history', sa.Boolean(), nullable=True, comment='True se o atleta tem histórico de fractura(s) de stress. Activa: (1) monitorização de bmd_total_g_per_cm2 semestral; (2) rastreio de RED-S (energy availability < 30 kcal/kg FFM/dia); (3) avaliação de vitamin_d_25oh e rbc_calcium. Interacção com COL1A1 TT genótipo (menor BMD basal) e com estradiol_baixo em F (Tríade da atleta feminina). species_osseous_system.stress_fracture_risk_modifier.'),
    sa.Column('surgeries_relevant', sa.String(length=512), nullable=True, comment="Cirurgias relevantes para o programa de treino. Exemplos: 'Reconstrução LCA joelho D com tendão patelar (2021)', 'Artroscopia ombro E por SLAP (2020)'. Informa thresholds de carga seguros e exercícios contra-indicados."),
    sa.Column('dietary_pattern', sa.String(length=64), nullable=True, comment="Padrão alimentar predominante. Valores: 'omnivore' | 'mediterranean' | 'vegetarian' | 'vegan' | 'ketogenic' | 'low_carb' | 'plant_based_high_protein'. Informa: (1) risco de défices específicos (B12 em vegan; ferro heme em plant-based; DHA em plant-based + FADS1 TT); (2) composição do microbioma (F/B ratio, Bifidobacterium em alta fibra); (3) disponibilidade de creatina endógena (ausente em vegan)."),
    sa.Column('sleep_aids_used', sa.String(length=256), nullable=True, comment="Auxiliares de sono utilizados regularmente. Exemplos: 'melatonina 0.5mg', 'magnésio glicinato 400mg', 'nenhum', 'alprazolam 0.5mg'. Benzodiazepinas e Z-drugs suprimem SWS e REM → interpretar sleep_sws_percentage e rem_percentage com cautela. Álcool ao jantar (> 2 unidades) → supressão de REM na primeira metade do sono → deficit de memória motora."),
    sa.Column('supplements_current', sa.Text(), nullable=True, comment="Lista de suplementos em uso no momento da avaliação (formato livre). Exemplos: 'creatina monohidratada 5g/dia, beta-alanina 4g/dia, cafeína 200mg pré-treino, vitamina D 4000 UI/dia, ómega-3 3g EPA+DHA/dia'. Crítico para interpretar biomarkers: creatina → creatinina sérica elevada (não confundir com insuficiência renal); proteína em pó → ureia elevada; ferro suplementar → ferritina elevada (pode mascarar sobrecarga em HFE). Permite calcular gap entre ingestão total e necessidades prescritas."),
    sa.Column('medications_chronic', sa.Text(), nullable=True, comment="Medicação crónica relevante para o programa fisiológico. Exemplos: 'levotiroxina 50μg/dia (hipotiroidismo)', 'metformina 500mg'. Impactos conhecidos: beta-bloqueantes → FCmax artificial < real → NUNCA usar para calcular zonas; metformina → supressão de complexo I mitocondrial → reduz produção de lactato → LT1 artificialmente baixo no teste incremental; SSRI → supressão REM. Lista não-exhaustiva: documentar para interpretar anomalias nos testes."),
    sa.Column('smoking_status', sa.String(length=32), nullable=True, comment="'never' | 'ex_smoker' | 'current' | 'occasional'. Tabagismo activo: redução de VO2max (HbCO↑), aceleração de DunedinPACE e GrimAge, telómeros mais curtos. Ex-fumador: GrimAge permanentemente modificado pelo histórico de tabagismo (inclui 'pack-years' como input do algoritmo GrimAge)."),
    sa.Column('alcohol_units_per_week', sa.Float(), nullable=True, comment='Consumo médio de álcool. Unidade: unidades padrão/semana (1 unidade = 10g etanol). Referência de baixo risco: H < 14 unidades/sem; F < 11 unidades/sem. Álcool > 3 unidades em noite de treino pesado → supressão de síntese proteica pós-exercício em ~24% (Parr et al., 2014), supressão de testosterone_total, comprometimento de SWS e REM. species_endocrine.alcohol_androgen_suppression_modifier.'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id'),
    sa.UniqueConstraint('athlete_id'),
    sa.UniqueConstraint('athlete_id', name='uq_athlete_history_athlete')
    )
    op.create_table('athlete_microbiome',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('sample_date', sa.Date(), nullable=False, comment='Data de colheita da amostra fecal. Protocolo: amostra de manhã, antes de defecação após 12h de jejum nocturno, sem antibióticos nas 4 semanas anteriores, sem probióticos nas 2 semanas anteriores. Preservar em tampão RNAlater a −20°C até extracção. Para série temporal: baseline → 4 semanas de intervenção nutricional → re-avaliação (taxa de resposta do microbioma: ~2-4 semanas).'),
    sa.Column('sequencing_method', sa.String(length=64), nullable=True, comment="'16S_V3V4' | '16S_V4' | 'shotgun_WGS' | 'ITS_fungi'. O método determina a resolução taxonómica: 16S identifica género; WGS identifica espécie e permite inferência funcional (KEGG pathways, CAZymes, SCFA gene clusters). Impacta a interpretação dos rácios."),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('shannon_diversity_index', sa.Float(), nullable=True, comment="Índice de diversidade de Shannon (H'). Escala típica em humanos: 2.5-4.5. H' = −Σ(pi × ln(pi)) onde pi = proporção relativa do taxon i. Combina riqueza (número de espécies) e equitabilidade (distribuição). H' > 3.5 → microbioma diverso e resiliente → melhor resposta imunológica adaptativa e inata, maior produção de SCFAs, menor permeabilidade intestinal (species_gastrointestinal.microbiome_diversity_reference). H' < 2.5 → disbiose → risco de infecções respiratórias peri-competição, síntese reduzida de neurotransmissores (serotonina; ~90% produzida no intestino), menor absorção de micronutrientes. Atletas de ultra-endurance tendem a ter H' mais baixo por dietas restritivas e stress oxidativo GI durante provas longas."),
    sa.Column('species_richness', sa.Float(), nullable=True, comment='Riqueza de espécies observadas (OTUs/ASVs identificadas). Escala típica: 100-500 OTUs em sequenciação 16S com rarefacção a 10,000 reads. Complemento do Shannon: um microbioma pode ter alta riqueza mas baixa equitabilidade (uma espécie domina) → Shannon baixo. Riqueza > 300 OTUs → reservatório funcional amplo → maior redundância metabólica (se uma via é comprometida, outra espécie supre a função). Interacção com species_gastrointestinal.microbiome_richness_reference.'),
    sa.Column('chao1_estimate', sa.Float(), nullable=True, comment='Estimador Chao1 de riqueza total (inclui espécies raras não observadas). Sempre ≥ species_richness observada. Razão Chao1/richness_observada → proporção do microbioma ainda não capturada pela profundidade de sequenciação actual. Chao1 > 500 → microbioma rico em espécies raras → reserva funcional metabólica elevada para adaptação a mudanças de dieta e stress fisiológico.'),
    sa.Column('firmicutes_bacteroidetes_ratio', sa.Float(), nullable=True, comment='Rácio Firmicutes / Bacteroidetes (F/B ratio). Referência saudável: 0.5-2.5. Firmicutes (Lachnospiraceae, Ruminococcaceae, Clostridia) → produtores de butirato; eficiência de extracção calórica dos carbohidratos. Bacteroidetes (Bacteroides, Prevotella) → produtores de propionato e acetato; regulação do metabolismo lipídico hepático. F/B > 3.0 → associado a obesidade, maior extracção calórica, disbiose metabólica; compromisso de species_bioenergetics.caloric_extraction_efficiency. F/B < 0.3 → dominância de Bacteroidetes; pode indicar dieta muito alta em fibra mas baixa em proteína animal. Em atletas de endurance: F/B tende para 1.0-1.5 com dieta mista equilibrada.'),
    sa.Column('proteobacteria_percentage', sa.Float(), nullable=True, comment='Abundância relativa de Proteobacteria (%). Referência saudável: < 5%. Proteobacteria incluem E. coli, Helicobacter, Salmonella e outros patóbiontes gram-negativos com LPS na parede celular. Proteobacteria > 10% → marcador de disbiose inflamatória → aumento de LPS circulante (endotoxemia metabólica) → activação de TLR4 → NF-κB → IL-6, TNF-α → resistência à insulina e inflamação sistémica (species_immune_microbiome.lps_endotoxin_threshold).'),
    sa.Column('akkermansia_muciniphila_pct', sa.Float(), nullable=True, comment="Abundância relativa de Akkermansia muciniphila (%). Referência desejável em atletas: 1-5% (0.5-8% em adultos saudáveis). A. muciniphila coloniza a camada de muco intestinal (produce mucinases). Funções: reforço da barreira intestinal (aumenta expressão de claudina-3 e occludina), redução de permeabilidade, activação do receptor GLP-1 → maior sensibilidade à insulina (HOMA-IR ↓). A. muciniphila < 0.1% → barreira intestinal comprometida → 'leaky gut' → endotoxemia → inflamação sistémica (species_gastrointestinal.mucosal_barrier_integrity). Exercício aeróbio moderado (>150 min/sem) aumenta A. muciniphila; ultra-endurance de alta intensidade pode reduzi-la transitoriamente."),
    sa.Column('faecalibacterium_prausnitzii_pct', sa.Float(), nullable=True, comment='Abundância relativa de Faecalibacterium prausnitzii (%). Referência desejável: 5-15% (é uma das bactérias mais abundantes em humanos saudáveis). F. prausnitzii é o principal produtor de butirato intestinal via via de fermentação de acetato e lactato. Butirato: (1) fuel primário dos colonócitos (>70% energia); (2) inibidor de HDAC → supressão epigenética de genes pró-inflamatórios; (3) activação de receptores GPR41/GPR43 → secreção de PYY e GLP-1 → saciedade e controlo glicémico. F. prausnitzii < 2% → risco de doença inflamatória intestinal, maior permeabilidade → impacta species_gastrointestinal.butyrate_production e species_immune_microbiome.regulatory_t_cell_induction.'),
    sa.Column('veillonella_spp_pct', sa.Float(), nullable=True, comment='Abundância relativa de Veillonella spp. (%). Referência em atletas de elite (dados Scheiman et al., Nature Medicine 2019): 2-8% (significativamente superior à população sedentária). Veillonella converte lactato muscular (transportado para o lúmen intestinal) em propionato → absorvido pelo fígado → gluconeogénese e síntese de corpos cetónicos → substrato energético alternativo durante esforço prolongado. Ciclo lactato-propionato: músculo → Veillonella → propionato → fígado → glucose/cetona → músculo. Atletas com Veillonella > 5% apresentam melhor tempo em provas de resistência de 60 min+ (species_bioenergetics.lactate_recycling_efficiency). Aumenta com treino de endurance de alto volume; é um biomarcador emergente de adaptação ao treino de resistência.'),
    sa.Column('lactobacillus_spp_pct', sa.Float(), nullable=True, comment='Abundância relativa de Lactobacillus spp. (%). Referência: 0.1-5% no cólon (maior no intestino delgado). Lactobacillus produz ácido láctico (L e D-lactato), bacteriocinas e H₂O₂ → inibição de patóbiontes. Estimula células dendríticas intestinais → diferenciação Treg (tolerância imunológica) e produção de IgA secretora. Lactobacillus > 1% → menor incidência de URTI (upper respiratory tract infections) em atletas durante picos de carga de treino (species_immune_microbiome.mucosal_immunity_lactobacillus_support). Suplementação com L. acidophilus + L. rhamnosus GG → reduz URTI em 50% em atletas de endurance (dados de Haywood et al., 2014).'),
    sa.Column('bifidobacterium_spp_pct', sa.Float(), nullable=True, comment='Abundância relativa de Bifidobacterium spp. (%). Referência adulto saudável: 3-8% (declina com a idade). Bifidobacterium fermenta oligossacarídeos não-digestíveis (FOS, GOS, inulina) → acetato e lactato → cross-feeding para produtores de butirato como F. prausnitzii. Produz vitaminas B (B1, B2, B6, B9, B12 numa fracção menor), aminoácidos essenciais, e modula a resposta imunológica mucosal via TLR2. Bifidobacterium < 1% → défice de fermentação de fibra prebiótica → redução do cross-feeding de butirato → intestino mais permeável (species_gastrointestinal.prebiotic_fermentation_capacity).'),
    sa.Column('ruminococcus_spp_pct', sa.Float(), nullable=True, comment='Abundância relativa de Ruminococcus spp. (%). Referência: 2-8%. Ruminococcus champanellensis e R. bromii são os principais degradadores de amido resistente e celulose → produção de butirato e acetato. Críticos para atletas com dieta alta em carbohidratos complexos (batata-doce, aveia, leguminosas). Ruminococcus > 5% associado a maior eficiência de síntese de glicogénio via butirato → estimulação de AMPK → GLUT4 → captação muscular de glicose (species_bioenergetics.glycogen_synthesis_microbiome_modifier).'),
    sa.Column('butyrate_mmol_per_kg', sa.Float(), nullable=True, comment='Butirato fecal (ácido butírico). Unidade: mmol/kg de fezes húmidas. Referência: 5-20 mmol/kg. O butirato é o SCFA mais clinicamente relevante: (1) fuel primário colonócitos (oxidado em beta-oxidação mitocondrial); (2) inibidor de HDAC classes I/II → desacetilação de histonas → supressão NF-κB → menor expressão de IL-6, IL-1β, TNF-α; (3) activa GPR109a (receptor de niacina) em macrófagos → polarização M2; (4) cruza a BHE em pequenas quantidades → suporte de astrocitos. Butirato < 5 mmol/kg → inflamação intestinal crónica de baixo grau → impacta species_immune_microbiome.regulatory_t_cell_induction e species_gastrointestinal.colonocyte_fuel_efficiency.'),
    sa.Column('propionate_mmol_per_kg', sa.Float(), nullable=True, comment='Propionato fecal (ácido propiónico). Unidade: mmol/kg de fezes húmidas. Referência: 5-25 mmol/kg. O propionato é produzido por Bacteroidetes e Veillonella spp. → absorvido pelo fígado via veia porta → substrato gluconeogénico (ciclo de Krebs via succinato) e regulador do colesterol hepático (inibição da HMG-CoA redutase). Em atletas: propionato elevado → gluconeogénese hepática mais eficiente em esforços prolongados → menor catabolismo de aminoácidos muscular (species_bioenergetics.hepatic_gluconeogenesis_scfa_modifier e species_hepatic.gluconeogenesis_substrate_availability).'),
    sa.Column('acetate_mmol_per_kg', sa.Float(), nullable=True, comment='Acetato fecal (ácido acético). Unidade: mmol/kg de fezes húmidas. Referência: 20-70 mmol/kg (é o SCFA mais abundante, ~60% do total). O acetato entra na circulação sistémica e é utilizado como: (1) substrato de acetil-CoA no ciclo de Krebs muscular e hepático; (2) precursor de corpos cetónicos nos hepatócitos; (3) sinal de saciedade via activação de GPR43 em adipócitos e GPR41 no sistema nervoso entérico. Acetato elevado correlaciona-se com maior diversidade de Firmicutes e alimenta o cross-feeding para produtores de butirato (species_bioenergetics.acetate_oxidation_rate).'),
    sa.Column('zonulin_ng_per_ml', sa.Float(), nullable=True, comment="Zonulina sérica. Unidade: ng/mL. Referência saudável: < 45 ng/mL (método ELISA Immundiagnostik). A zonulina é uma proteína endógena (pre-haptoglobina 2) que regula a abertura das junções estreitas epiteliais (claudinas, occludina, ZO-1/2). Zonulina elevada → junções estreitas abertas → 'leaky gut' → translocação de LPS, péptidos alimentares e fragmentos bacterianos para a circulação → endotoxemia → activação TLR4/NF-κB → inflamação sistémica crónica (species_gastrointestinal.tight_junction_integrity_threshold). Em atletas: esforços >75% VO2max por >60 min → hipertermia intestinal → zonulina transitoriamente elevada até 2h pós-exercício (fisiológico); cronicamente elevada → RED-S ou disbiose activa."),
    sa.Column('lps_eu_per_ml', sa.Float(), nullable=True, comment='LPS (Lipopolissacarídeo) sérico — endotoxina de gram-negativos. Unidade: EU/mL (Endotoxin Units). Referência: < 1.0 EU/mL em circulação sistémica. LPS é o principal activador do receptor TLR4/MD-2 → MyD88 → NF-κB → cascata inflamatória (IL-6, TNF-α, IL-1β, PCR). Endotoxemia metabólica crónica (LPS 2-3 EU/mL) → resistência à insulina, adipogénese visceral, aterogénese. Correlaciona-se com Proteobacteria elevada e zonulina elevada (species_immune_microbiome.lps_endotoxin_threshold e species_cardiovascular.endotoxin_atherogenic_modifier).'),
    sa.Column('siga_mg_per_dl', sa.Float(), nullable=True, comment='IgA secretora fecal (sIgA). Unidade: mg/dL ou mg/g de fezes. Referência fecal: 5-20 mg/dL (variabilidade alta entre métodos). A sIgA é o principal anticorpo da imunidade mucosal intestinal: neutraliza patógenos e toxinas no lúmen sem ativar complemento (resposta inflamatória mínima). Produzida por células plasmáticas na lâmina própria sob regulação de IL-10, TGF-β e células Treg. sIgA fecal baixa (<3 mg/dL) → imunidade mucosal comprometida → maior susceptibilidade a gastroenterites de treino e competição (species_immune_microbiome.mucosal_siga_threshold). sIgA salivar (colhida em repouso matinal, medida separadamente) é marcador do estado imunológico sistémico (ver athlete_psych para HRV).'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
    op.create_table('athlete_performance',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('assessment_date', sa.Date(), nullable=False, comment='Data da avaliação de performance. Protocolo: 72h de recuperação após última sessão de alta intensidade, refeição padronizada 3h antes, sem cafeína 12h antes. Sequência recomendada: biomecânica (manhã) → cardiorrespiratório (tarde) com 4h de intervalo para evitar fadiga residual.'),
    sa.Column('assessment_context', sa.String(length=64), nullable=True, comment="'pre_season' | 'mid_season' | 'post_season' | 'return_to_sport' | 'ad_hoc'. Contextualiza o resultado na periodização anual."),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('vo2max_ml_per_kg_min', sa.Float(), nullable=True, comment='VO2max — Consumo máximo de oxigénio relativo ao peso corporal. Unidade: mL/kg/min. Referência elite H endurance: 75-90 mL/kg/min; F: 65-80 mL/kg/min. Recordes absolutos: H ~97 mL/kg/min (Oskar Svendsen); F ~78 mL/kg/min. CPI_VO2max = vo2max_atleta / species_cardiovascular.vo2max_ceiling. VO2max = Débito Cardíaco × diferença arteriovenosa de O₂ (Fick: VO2 = DC × (CaO₂ − CvO₂)). Limitar superiormente pelo: (1) transporte de O₂ (Hb × SaO₂ × DC); (2) difusão alveolar (DLCO); (3) densidade capilar muscular (VEGF genótipo); (4) densidade mitocondrial (PPARGC1A genótipo). Modifica species_cardiovascular.vo2max_ceiling como denominador do CPI.'),
    sa.Column('vo2max_absolute_l_per_min', sa.Float(), nullable=True, comment='VO2max absoluto. Unidade: L/min. Relevante para desportos com peso fixo (remo, ciclismo de pista, natação). VO2max_absoluto = vo2max_ml_per_kg_min × peso_kg / 1000. Elite remo H: 6.5-7.5 L/min.'),
    sa.Column('ventilatory_threshold_1_pct_vo2max', sa.Float(), nullable=True, comment='VT1 — Primeiro Limiar Ventilatório (Aerobic Threshold / LT1). Unidade: % do VO2max. O VT1 corresponde ao início do aumento não-linear do VE/VCO₂ e à deflexão do RER — ponto onde a lactato sanguíneo começa a acumular acima da baseline (tipicamente 1.5-2.0 mmol/L). Atleta de endurance elite: VT1 a 70-80% VO2max. Zona 1/2 de treino: intensidades abaixo do VT1 (oxidação lipídica máxima). Interage com species_bioenergetics.aerobic_threshold_reference e species_lipid_metabolism.fat_oxidation_peak_intensity.'),
    sa.Column('lactate_threshold_1_mmol', sa.Float(), nullable=True, comment='LT1 — Concentração de lactato no primeiro limiar. Unidade: mmol/L. Referência: ~1.5-2.0 mmol/L (ponto de deflexão da curva lactato-intensidade). Atletas de ultra-endurance: LT1 pode ser tão baixo como 1.0-1.2 mmol/L por maior capacidade de clearance e oxidação de lactato. Interacção com Veillonella spp. (microbioma): maior abundância → maior conversão de lactato em propionato → clearance mais eficiente (species_bioenergetics.lactate_clearance_rate).'),
    sa.Column('lactate_threshold_2_mmol', sa.Float(), nullable=True, comment='LT2/MLSS — Segundo Limiar de Lactato / Máximo Estado Estável de Lactato. Unidade: mmol/L. Referência: 3.5-5.5 mmol/L (convencionalmente 4.0 mmol/L — OnForm/Mader). LT2 = limiar anaeróbio individual; potência/pace acima do MLSS não é sustentável por > 30-60 min (lactato acumula progressivamente). Zona 4/5 de treino: intervalo entre LT2 e VO2max. species_bioenergetics.lactate_threshold_2_reference.'),
    sa.Column('ventilatory_threshold_2_pct_vo2max', sa.Float(), nullable=True, comment='VT2 — Segundo Limiar Ventilatório (Respiratory Compensation Point). Unidade: % do VO2max. O VT2 corresponde ao ponto onde o VE aumenta mais steeply que o VCO₂ (hiperventilação de compensação da acidose metabólica). Atleta elite endurance: VT2 a 85-92% VO2max. Distância VT1-VT2 (zona aeróbia-anaeróbia) → espaço para treino tempo. species_cardiovascular.ventilatory_threshold_2_reference.'),
    sa.Column('fatmax_pct_vo2max', sa.Float(), nullable=True, comment="FATmax — Intensidade de máxima oxidação lipídica. Unidade: % do VO2max. Calculado a partir do teste de oxidação de substratos (RER → VCO₂/VO₂). FATmax = intensidade onde (1.695 × VO₂ − 1.701 × VCO₂) é máximo. Referência: 45-65% VO2max em atletas de endurance. FATmax abaixo de 45% → baixa flexibilidade metabólica → dependência precoce de glicose → 'hitting the wall' em ultra. Interacção com FADS1 genótipo (conversão ALA→DHA) e omega_3_index (fluidez de membrana mitocondrial → eficiência de beta-oxidação). species_lipid_metabolism.fat_oxidation_max_rate e species_mitochondrial.beta_oxidation_capacity."),
    sa.Column('max_fat_oxidation_g_per_min', sa.Float(), nullable=True, comment="MFO — Máxima Oxidação de Gordura (g/min). Referência atletas endurance: 0.5-1.5 g/min. Elite 'fat-adapted': >1.2 g/min. Calculado: MFO = 1.695 × VO₂(FATmax) − 1.701 × VCO₂(FATmax) [g/min]. MFO > 1.2 g/min → 'metabolic efficiency' superior → menor depleção de glicogénio nas primeiras horas de esforço → vantagem em provas >3h."),
    sa.Column('max_heart_rate_bpm', sa.Float(), nullable=True, comment='FC máxima medida em esforço máximo incremental. Unidade: bpm. NUNCA usar fórmulas (220−idade; Tanaka); sempre medida. Referência: altamente individual; decresce ~1 bpm/ano após os 25. FC máxima é o tecto do débito cardíaco por frequência: DC_max = FCmax × VS_max. species_cardiovascular.max_heart_rate_reference.'),
    sa.Column('heart_rate_recovery_1min_bpm', sa.Float(), nullable=True, comment='Recuperação da FC ao 1º minuto pós-esforço máximo (HRR1). Unidade: bpm de queda. Referência: > 12 bpm (atleta saudável); elite endurance: 25-40 bpm/min. HRR1 < 12 bpm → risco cardiovascular aumentado (Nishime et al., NEJM 1999). HRR1 reflecte o tónus vagal e a reactivação parassimpática pós-esforço — correlaciona-se com HRV RMSSD em repouso (species_cardiovascular.parasympathetic_recovery_rate).'),
    sa.Column('respiratory_exchange_ratio_max', sa.Float(), nullable=True, comment='RER máximo no pico do teste incremental. Dimensionless (VCO₂/VO₂). RER ≥ 1.10 é critério de esforço máximo atingido. RER < 1.05 no pico → esforço submáximo → VO2max pode estar subestimado. Verifica que o protocolo foi realmente máximo antes de registar vo2max.'),
    sa.Column('cmj_height_cm', sa.Float(), nullable=True, comment='CMJ — Counter Movement Jump height. Unidade: cm. Medição: plataforma de força (gold-standard) ou tapete de contacto / acelerómetro (Myotest, PUSH Band). Referência H atletas desporto colectivo: 35-55 cm; F: 28-42 cm. CMJ mede a potência de pico dos extensores do membro inferior (cadeia posterior: glúteos, isquiotibiais, gémeos) em regime pliométrico (ciclo alongamento-encurtamento, SSC). CPI_CMJ = cmj_height / species_neuromuscular.ssc_jump_height_ceiling. Monitorização: queda de CMJ > 10% vs. baseline → fadiga neuromuscular significativa → reduzir carga de treino.'),
    sa.Column('cmj_rsi_score', sa.Float(), nullable=True, comment='RSI — Reactive Strength Index (CMJ). Dimensionless. RSI = Altura de salto (m) / Tempo de contacto (s). Referência elite: RSI > 2.5; força explosiva alto nível: >3.0. O RSI mede a capacidade de produção rápida de força no SSC rápido (tempo de contacto < 250ms) — qualidade de mola do tendão e reflexo miotático. RSI < 1.5 → défice de stiffness tendinosa e/ou co-activação reflexa. Interage com COL5A1 genótipo (rigidez tendinosa genética) e tendon_stiffness_n_per_mm medida por ultrassom (species_musculoskeletal.tendon_stiffness_ceiling).'),
    sa.Column('imtp_peak_force_n', sa.Float(), nullable=True, comment='IMTP — Isometric Mid-Thigh Pull peak force. Unidade: N. Protocolo: plataforma de força, ângulo joelho 125-145°, 3s de pull máximo. Referência H atletas força/colectivo: 2000-3500 N. IMTP mede a força isométrica máxima do sistema triplo de extensão (tornozelo-joelho-anca); correlaciona-se com pico de produção de força em movimentos dinâmicos (sprint, mudança de direcção). IMTP/BW (força relativa ao peso) ≥ 3.0 → excelente para desportos de potência (species_neuromuscular.isometric_peak_force_ceiling). Assimetria IMTP esquerdo/direito > 10% → risco de lesão do membro inferior dominante.'),
    sa.Column('handgrip_dominant_kg', sa.Float(), nullable=True, comment='Força de preensão manual — mão dominante. Unidade: kg (dinamómetro Jamar). Protocolo: 3 tentativas com 30s de intervalo; registar o maior valor. Referência H 20-30 anos: 50-70 kg; F: 30-45 kg. A força de preensão é um marcador proxy de força total e preditor independente de mortalidade all-cause (Leong et al., Lancet 2015: cada 5 kg de redução → +16% mortalidade cardiovascular). CPI_grip = handgrip_dominant / species_neuromuscular.handgrip_force_ceiling.'),
    sa.Column('handgrip_nondominant_kg', sa.Float(), nullable=True, comment='Força de preensão manual — mão não-dominante. Unidade: kg. Assimetria normal: 5-10% (dominante > não-dominante). Assimetria > 15% → disfunção neuromuscular unilateral ou lesão. Rácio dominante/não-dominante: registar como indicador de lateralidade funcional.'),
    sa.Column('ankle_dorsiflexion_dominant_deg', sa.Float(), nullable=True, comment='Amplitude de dorsiflexão do tornozelo — membro dominante. Unidade: graus. Teste: Weight-bearing lunge test (WBLT) — distância pé-parede em cm convertida em graus (tan⁻¹(d/h)). Referência funcional: ≥ 35-38° (ou ≥ 10 cm no WBLT). Dorsiflexão < 30° → compensação biomecânica: valgo dinâmico do joelho, aumento de carga patelar e Aquiliana, risco de fascite plantar. Interage com COL5A1 e TNXB genótipos (laxidez articular). species_musculoskeletal.ankle_mobility_reference.'),
    sa.Column('ankle_dorsiflexion_nondominant_deg', sa.Float(), nullable=True, comment='Amplitude de dorsiflexão — membro não-dominante. Unidade: graus. Assimetria > 5° entre membros → investigar restrição unilateral (encurtamento do sóleo/gémeo, aderências cicatriciais de lesões anteriores). Assimetria bilateral correlaciona-se com padrão de lesão de tornozelo recorrente.'),
    sa.Column('thoracic_rotation_dominant_deg', sa.Float(), nullable=True, comment='Rotação torácica — direcção dominante. Unidade: graus. Teste: seated thoracic rotation com pelvis fixada. Referência funcional: ≥ 50° bilateral. Rotação torácica restrita → compensação lombar → risco de lombalgia em desportos de rotação (golfe, ténis, basebol, remo). species_musculoskeletal.spinal_mobility_reference.'),
    sa.Column('thoracic_rotation_nondominant_deg', sa.Float(), nullable=True, comment='Rotação torácica — direcção não-dominante. Unidade: graus. Assimetria > 10° → investigar disfunção costovertebral unilateral ou padrão de sobrecarga rotacional crónica (overuse de desportos assimétricos).'),
    sa.Column('tendon_cross_sectional_area_mm2', sa.Float(), nullable=True, comment='CSA do tendão-alvo (patelar ou Aquiles, conforme protocolo). Unidade: mm². Medição: ultrassom B-mode em corte transversal a 2-3 cm da inserção. Referência tendão patelar H: 50-100 mm²; Aquiles H: 45-80 mm². CSA aumentada (>120 mm² patelar) → tendinopatia crónica com espessamento. CSA reduzida para o nível de treino → hipotrofia tendinosa → risco de rotura. species_musculoskeletal.tendon_morphology_reference.'),
    sa.Column('tendon_stiffness_n_per_mm', sa.Float(), nullable=True, comment="Rigidez tendinosa (stiffness). Unidade: N/mm. Medição: ultrassom sonotransdutor + dinamómetro isocinético (método de alongamento controlado com imaging simultâneo de junção miotendínosa). Referência Aquiles H treinado: 100-250 N/mm. Stiffness elevada → transmissão de força mais eficiente → RSI mais alto. Stiffness baixa → maior armazenamento de energia elástica mas menor eficiência de retorno → 'energia desperdiçada' no SSC. Interage com COL5A1 genótipo (architecture intrínseca das fibrilas): TT homozigoto → maior stiffness basal (species_musculoskeletal.tendon_stiffness_ceiling)."),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
    op.create_table('athlete_psych',
    sa.Column('id', sa.UUID(), nullable=False),
    sa.Column('athlete_id', sa.UUID(), nullable=False),
    sa.Column('assessment_date', sa.Date(), nullable=False, comment='Data da avaliação psicológica. Protocolo: administrar RESTQ-Sport e POMS na mesma semana, preferencialmente ao mesmo dia da semana para controlar variabilidade intra-semanal. MCTQ: completar com dados de 4 semanas de sono. HRV: média de 7 dias consecutivos de medição matinal em repouso supino.'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False),
    sa.Column('mctq_msf_sc', sa.Float(), nullable=True, comment="MCTQ MSFsc — Munich Chronotype Questionnaire, Sleep-corrected Midpoint of Sleep on Free Days. Unidade: horas decimais (ex: 3.5 = 03:30). Desenvolvido por Roenneberg et al.; é o gold-standard de avaliação de cronotipo sem viés de comportamento social. MSFsc < 2.0h → cronotipo extremamente matutino ('cegonha extrema'). MSFsc 2.0-4.0h → cronotipo intermédio (maioria da população). MSFsc > 5.0h → cronotipo vespertino ('coruja'); correlaciona-se com CLOCK rs1801260 CC e PER2 variantes. species_chronobiology.chronotype_phase_reference: pico de performance ≈ MSFsc + 7-8h (máximo de temperatura corporal). Informa horário óptimo de competição, treino e suplementação de cafeína."),
    sa.Column('social_jetlag_hours', sa.Float(), nullable=True, comment="Social Jetlag (SJL). Unidade: horas. Fórmula: SJL = |MSF − MSW| onde MSF = midpoint sleep dias livres; MSW = midpoint sleep dias de treino/trabalho. SJL representa o 'jetlag interno' causado pelo conflito entre o relógio biológico e os horários sociais/de treino impostos. SJL > 2h → disrupção circadiana significativa → elevação de cortisol nocturno, supressão de melatonina, comprometimento da fase SWS do sono (species_chronobiology.social_jetlag_threshold). SJL > 2h associado a aumento de 33% do risco de obesidade e 1.5× risco de síndrome metabólica (Roenneberg et al.). Objectivo: SJL < 1h através de sincronização de horários de treino com o cronotipo natural."),
    sa.Column('pss_score', sa.Integer(), nullable=True, comment='PSS — Perceived Stress Scale (Cohen et al., 1983). Escala: 0-40. 10 itens, Likert 0-4; itens positivos invertidos. Classificação: 0-13 = stress baixo; 14-26 = stress moderado; 27-40 = stress elevado. PSS > 26 → activação crónica do eixo HPA → cortisol_am elevado → catabolismo muscular, supressão imunológica, disrupção do sono (species_endocrine.hpa_activation_stress_threshold). PSS correlaciona-se com HRV RMSSD invertidamente: PSS 27+ → RMSSD tipicamente < 40ms em atletas. Monitorizar conjuntamente com RESTQ-Sport para distinção entre stress de treino (recuperável) e stress psicossocial (multifactorial).'),
    sa.Column('restq_sport_stress_score', sa.Float(), nullable=True, comment='RESTQ-Sport — Recovery-Stress Questionnaire for Athletes (Kellmann & Kallus). Sub-escala de Stress total (média das 7 escalas de stress). Escala Likert 0-6 por item; maior = mais frequente. Stress total < 2.0 → carga de treino bem tolerada. Stress total > 3.5 → sobretreinamento iminente → protocolo de tapering. species_immune_microbiome.training_stress_threshold.'),
    sa.Column('restq_sport_recovery_score', sa.Float(), nullable=True, comment='RESTQ-Sport — Sub-escala de Recuperação total (média das 5 escalas de recuperação). Recuperação > 4.0 → recuperação adequada para carga progressiva. Recuperação < 2.5 → défice de recuperação → reduzir volume 20-30%, aumentar sono, protocolo nutricional de recuperação. Rácio Recuperação/Stress > 1.2 → estado funcional positivo. Rácio < 0.8 → overreaching não-funcional (species_endocrine.recovery_deficit_threshold).'),
    sa.Column('poms_tmd_score', sa.Float(), nullable=True, comment="POMS — Profile of Mood States, Total Mood Disturbance (TMD). Fórmula: TMD = (Tensão + Depressão + Hostilidade + Fadiga + Confusão) − Vigor. Escala normalizada: TMD negativo → 'iceberg profile' (Vigor elevado, outros estados baixos) — perfil clássico de atleta bem-treinado. TMD positivo → desequilíbrio emocional → risco de overtraining síndrome. TMD > +20 → indicador de overtreino severo (Morgan et al., 1987). Monitorização semanal rápida (6 escalas, 65 itens ou versão curta 30 itens). species_neural_cognitive.mood_state_performance_threshold."),
    sa.Column('dass21_depression_score', sa.Integer(), nullable=True, comment='DASS-21 — Depression Anxiety Stress Scales, sub-escala Depressão. Escala: 0-42 (7 itens × máx 6, × 2 para normalizar ao DASS-42). Classificação: 0-9 normal; 10-13 leve; 14-20 moderada; 21-27 severa; >28 extrema. Depressão no contexto desportivo: monitorizar em pós-lesão grave, desempenhamento prolongado, ou atletas com BDNF Val66Met AA (menor neuroplasticidade induzida pelo exercício). Score > 13 → referenciação para psicólogo do desporto (species_neural_cognitive.depression_risk_threshold).'),
    sa.Column('dass21_anxiety_score', sa.Integer(), nullable=True, comment='DASS-21 — Sub-escala Ansiedade. Escala: 0-42. Classificação: 0-7 normal; 8-9 leve; 10-14 moderada; 15-19 severa; >20 extrema. Ansiedade de pré-competição e ansiedade social de performance são frequentes em atletas — distinguir ansiedade facilitadora (leve, activadora) de ansiedade debilitante (moderada-severa). SLC6A4 SS homozigoto → maior hiperreactividade a stressores → scores de ansiedade mais elevados (species_neural_cognitive.anxiety_serotonin_modifier).'),
    sa.Column('dass21_stress_score', sa.Integer(), nullable=True, comment='DASS-21 — Sub-escala Stress (tensão e agitação). Escala: 0-42. Classificação: 0-14 normal; 15-18 leve; 19-25 moderada; 26-33 severa; >34 extrema. A sub-escala stress do DASS-21 é mais sensível a stress agudo que o PSS (que mede stress percebido crónico). Stress DASS21 > 18 persistente → activação HPA crónica → perfil de cortisol aplanado, DHEA-S baixo (species_endocrine.hpa_chronic_stress_axis).'),
    sa.Column('hexaco_honesty_humility', sa.Float(), nullable=True, comment='HEXACO — Dimensão Honesty-Humility. Escala: 1.0-5.0 (média dos itens). Avalia sinceridade, equanimidade, não-gananciosidade e modéstia. Alto H-H → menor propensão para comportamentos anti-desportivos e doping. Relevante para ética desportiva e adesão a protocolos (species_neural_cognitive.integrity_behavioral_trait).'),
    sa.Column('hexaco_emotionality', sa.Float(), nullable=True, comment='HEXACO — Dimensão Emotionality. Escala: 1.0-5.0. Avalia medo, ansiedade, dependência e sentimentalismo. Alto E → maior sensibilidade emocional → perfil de ansiedade de pré-competição elevada. Interacção com SLC6A4 SS e COMT Met/Met. Em lesão: alto E → pior regulação emocional no processo de reabilitação.'),
    sa.Column('hexaco_extraversion', sa.Float(), nullable=True, comment='HEXACO — Dimensão Extraversion. Escala: 1.0-5.0. Avalia auto-estima social, atrevimento, sociabilidade e animação. Alto X → maior motivação extrínseca (audiência, equipa) → vantagem em desportos colectivos e de alto espectáculo. DRD2 A2A2 → maior recompensa intrínseca → pode compensar baixo X em desportos individuais de resistência.'),
    sa.Column('hexaco_agreeableness', sa.Float(), nullable=True, comment='HEXACO — Dimensão Agreeableness. Escala: 1.0-5.0. Avalia perdão, gentileza, flexibilidade e paciência. Baixo A → maior agressividade competitiva → vantagem em desportos de contacto; maior risco de conflito com equipa técnica. Monitorizar em atletas de alto rendimento com COMT Val/Val (baixa ruminação, alta tolerância ao stress agudo) e baixo A (species_neural_cognitive.competitive_aggressiveness_trait).'),
    sa.Column('hexaco_conscientiousness', sa.Float(), nullable=True, comment='HEXACO — Dimensão Conscientiousness. Escala: 1.0-5.0. Avalia organização, diligência, perfecionismo e prudência. Alto C → maior adesão a protocolos de treino, nutrição e recuperação → é o preditor de personalidade mais forte de performance de longo-prazo. DRD2 A2A2 (maior recompensa com progressão gradual) + alto C → perfil ideal para periodização estruturada de longo-prazo. species_neural_cognitive.adherence_personality_trait.'),
    sa.Column('hexaco_openness', sa.Float(), nullable=True, comment='HEXACO — Dimensão Openness to Experience. Escala: 1.0-5.0. Avalia curiosidade estética, criatividade e inquisitividade. Alto O → maior abertura a novos métodos de treino, biohacking, tecnologias de monitorização. Relevante para adesão a intervenções nutricionais e de estilo de vida não-convencionais (crioterapia, jejum intermitente, altitude simulada).'),
    sa.Column('hrv_rmssd_baseline_ms', sa.Float(), nullable=True, comment='HRV RMSSD basal crónico (média de 7 dias em repouso supino, matinal). Unidade: ms. RMSSD = Root Mean Square of Successive Differences dos intervalos RR — reflecte o tónus parassimpático (nervo vago → nodo SA). Referência atleta elite: 70-120 ms; atleta recreativo: 40-80 ms; sedentário saudável: 25-50 ms. RMSSD basal é um dos mais robustos marcadores de estado de recuperação: queda >15% vs. baseline de 7 dias → reduzir carga de treino. Correlaciona-se com: tónus vagal (species_cardiovascular.vagal_tone_index), cortisol_am (HRV ↑ ↔ cortisol ↓), e PER3 VNTR (5/5 → RMSSD mais baixo após privação de sono).'),
    sa.Column('resting_heart_rate_bpm', sa.Float(), nullable=True, comment='FC em repouso basal crónica (média de 7 dias, medição matinal supino). Unidade: bpm. Referência atleta elite endurance: 35-50 bpm (bradicardia de treino = adaptação ao volume de treino aeróbio: aumento do VS, regulação vagal). FC repouso cronicamente > 60 bpm em atleta de endurance de alto volume → sinal de overtraining, infecção subclínica ou défice de sono. Aumento súbito > 5 bpm vs. baseline → intervenção de recuperação. species_cardiovascular.resting_heart_rate_reference.'),
    sa.Column('sleep_efficiency_percentage', sa.Float(), nullable=True, comment='Eficiência do sono basal crónica (wearable — Oura, Garmin, Whoop). Unidade: %. Fórmula: (Tempo total de sono / Tempo na cama) × 100. Referência: ≥ 85% (PSG gold-standard); wearable ≥ 80% como proxy. Eficiência < 80% → fragmentação do sono → redução de SWS e REM → comprometimento da consolidação de memória motora, secreção de GH (70% GH secretada em SWS pulsátil) e clearance glinfática cerebral (species_chronobiology.sleep_efficiency_threshold e species_endocrine.growth_hormone_sleep_dependency).'),
    sa.Column('sleep_duration_hours', sa.Float(), nullable=True, comment='Duração média do sono (wearable ou diário). Unidade: horas decimais. Referência atletas: 8-10h (recomendação ACSM/NSCA para atletas de alto rendimento em fase de carga). Sono < 7h cronicamente → redução de testosterone_total em ~10-15% (Leproult & Van Cauter, JAMA 2011), aumento de cortisol vespertino, comprometimento de BDNF e neuroplasticidade (species_endocrine.sleep_testosterone_dependency).'),
    sa.Column('sleep_sws_percentage', sa.Float(), nullable=True, comment='Percentagem de sono de ondas lentas (SWS / N3) no sono total. Unidade: %. Referência adulto jovem: 15-25% do sono total. SWS é a fase de maior secreção de GH, maior síntese proteica muscular e maior actividade de reparação celular. SWS < 10% → défice de GH nocturna → comprometimento de recuperação muscular após treino de força (species_endocrine.growth_hormone_sleep_dependency). SWS reduz com a idade (~2% por década após os 30); treino de alta intensidade no dia anterior aumenta SWS transitoriamente.'),
    sa.Column('sleep_rem_percentage', sa.Float(), nullable=True, comment='Percentagem de sono REM no sono total. Unidade: %. Referência: 20-25% do sono total. REM é a fase de: (1) consolidação de memória motora procedural (sequências técnicas, habilidades desportivas novas); (2) regulação emocional (via amígdala e córtex pré-frontal); (3) síntese de ACh e modulação serotoninérgica e noradrenérgica. REM < 15% → aprendizagem técnica comprometida e maior labilidade emocional (species_neural_cognitive.procedural_memory_consolidation_rem_dependency). REM suprimido por: álcool, cannabis, benzodiazepinas, beta-bloqueantes.'),
    sa.ForeignKeyConstraint(['athlete_id'], ['athlete_core.id'], ondelete='CASCADE'),
    sa.PrimaryKeyConstraint('id')
    )
